        const FIELDS: [PrCreateField; 2] = [PrCreateField::Title, PrCreateField::Body];
        let index = FIELDS.iter().position(|field| *field == self).unwrap_or(0);
        let next = move_wrapping(index, FIELDS.len(), delta);
