fn start_pr_action(
    item: WorkItem,
    action: PrAction,
    checkout: Option<PrCheckoutPlan>,
    merge_method: Option<MergeMethod>,
    config: Config,
    store: SnapshotStore,
    tx: UnboundedSender<AppMsg>,
) {
    tokio::spawn(async move {
        let item_id = item.id.clone();
        let item_kind = item.kind;
        if action == PrAction::Checkout {
            let Some(checkout) = checkout else {
                let _ = tx.send(AppMsg::PrCheckoutFinished {
                    result: Err("missing local checkout target".to_string()),
                });
                return;
            };
            let result = run_pr_checkout(item, checkout.directory).await;
            let _ = tx.send(AppMsg::PrCheckoutFinished { result });
            return;
        }

        let result = match item.number {
            Some(number) => match action {
                PrAction::Merge if item.kind == ItemKind::PullRequest => {
                    merge_pull_request(&item.repo, number, merge_method.unwrap_or_default())
                        .await
                        .map_err(|error| error.to_string())
                }
                PrAction::Close if item.kind == ItemKind::PullRequest => {
                    close_pull_request(&item.repo, number)
                        .await
                        .map_err(|error| error.to_string())
                }
                PrAction::Close if item.kind == ItemKind::Issue => close_issue(&item.repo, number)
                    .await
                    .map_err(|error| error.to_string()),
                PrAction::Reopen if item.kind == ItemKind::PullRequest => {
                    reopen_pull_request(&item.repo, number)
                        .await
                        .map_err(|error| error.to_string())
                }
                PrAction::Reopen if item.kind == ItemKind::Issue => {
                    reopen_issue(&item.repo, number)
                        .await
                        .map_err(|error| error.to_string())
                }
                PrAction::Approve if item.kind == ItemKind::PullRequest => {
                    approve_pull_request(&item.repo, number)
                        .await
                        .map_err(|error| error.to_string())
                }
                PrAction::EnableAutoMerge if item.kind == ItemKind::PullRequest => {
                    enable_pull_request_auto_merge(&item.repo, number)
                        .await
                        .map_err(|error| error.to_string())
                }
                PrAction::DisableAutoMerge if item.kind == ItemKind::PullRequest => {
                    disable_pull_request_auto_merge(&item.repo, number)
                        .await
                        .map_err(|error| error.to_string())
                }
                PrAction::Checkout => unreachable!("checkout is handled before remote PR actions"),
                PrAction::RerunFailedChecks if item.kind == ItemKind::PullRequest => {
                    rerun_failed_pull_request_checks(&item.repo, number)
                        .await
                        .map_err(|error| error.to_string())
                }
                PrAction::UpdateBranch if item.kind == ItemKind::PullRequest => {
                    update_pull_request_branch(&item.repo, number)
                        .await
                        .map_err(|error| error.to_string())
                }
                PrAction::ConvertToDraft if item.kind == ItemKind::PullRequest => {
                    convert_pull_request_to_draft(&item.repo, number)
                        .await
                        .map_err(|error| error.to_string())
                }
                PrAction::MarkReadyForReview if item.kind == ItemKind::PullRequest => {
                    mark_pull_request_ready_for_review(&item.repo, number)
                        .await
                        .map_err(|error| error.to_string())
                }
                PrAction::Merge
                | PrAction::Approve
                | PrAction::EnableAutoMerge
                | PrAction::DisableAutoMerge
                | PrAction::RerunFailedChecks
                | PrAction::UpdateBranch
                | PrAction::ConvertToDraft
                | PrAction::MarkReadyForReview => {
                    Err("selected item is not a pull request".to_string())
                }
                PrAction::Close | PrAction::Reopen => {
                    Err("selected item is not an issue or pull request".to_string())
                }
            },
            None => Err("selected item has no issue or pull request number".to_string()),
        };
        let should_refresh = result.is_ok();
        let _ = tx.send(AppMsg::PrActionFinished {
            item_id,
            item_kind,
            action,
            merge_method,
            result,
        });

        if should_refresh {
            if let Some(number) = item.number {
                let item_id = item.id.clone();
                let actions = fetch_pull_request_action_hints(&item.repo, number)
                    .await
                    .map_err(|error| error.to_string());
                let _ = tx.send(AppMsg::ActionHintsLoaded { item_id, actions });
            }
            let _ = tx.send(AppMsg::RefreshStarted {
                scope: RefreshScope::Full,
            });
            let sections = with_background_github_priority(refresh_dashboard(&config)).await;
            let mut save_error = None;
            for section in &sections {
                if section.error.is_some() {
                    continue;
                }
                if let Err(error) = store.save_section(section) {
                    let message = error.to_string();
                    warn!(error = %message, "failed to save refreshed snapshot after PR action");
                    save_error = Some(message);
                    break;
                }
            }
            let _ = tx.send(AppMsg::RefreshFinished {
                sections,
                save_error,
            });
        }
    });
}

fn start_milestones_load(item: WorkItem, tx: UnboundedSender<AppMsg>) {
    tokio::spawn(async move {
        let item_id = item.id.clone();
        let result = fetch_open_milestones(&item.repo)
            .await
            .map_err(|error| error.to_string());
        let _ = tx.send(AppMsg::MilestonesLoaded { item_id, result });
    });
}

fn start_milestone_change(
    item: WorkItem,
    choice: MilestoneChoice,
    config: Config,
    store: SnapshotStore,
    tx: UnboundedSender<AppMsg>,
) {
    tokio::spawn(async move {
        let item_id = item.id.clone();
        let mut changed_milestone = None;
        let result = match item.number {
            Some(number) => match resolve_milestone_choice(&item.repo, choice).await {
                Ok(milestone) => {
                    changed_milestone = milestone.clone();
                    change_issue_milestone(&item.repo, number, milestone.as_ref().map(|m| m.number))
                        .await
                        .map_err(|error| error.to_string())
                }
                Err(error) => Err(error),
            },
            None => Err("selected item has no issue or pull request number".to_string()),
        };
        let should_refresh = result.is_ok();
        let _ = tx.send(AppMsg::MilestoneChanged {
            item_id,
            milestone: changed_milestone,
            result,
        });

        if should_refresh {
            let _ = tx.send(AppMsg::RefreshStarted {
                scope: RefreshScope::Full,
            });
            let sections = with_background_github_priority(refresh_dashboard(&config)).await;
            let mut save_error = None;
            for section in &sections {
                if section.error.is_some() {
                    continue;
                }
                if let Err(error) = store.save_section(section) {
                    let message = error.to_string();
                    warn!(error = %message, "failed to save refreshed snapshot after milestone change");
                    save_error = Some(message);
                    break;
                }
            }
            let _ = tx.send(AppMsg::RefreshFinished {
                sections,
                save_error,
            });
        }
    });
}

async fn resolve_milestone_choice(
    repository: &str,
    choice: MilestoneChoice,
) -> std::result::Result<Option<Milestone>, String> {
    match choice {
        MilestoneChoice::Clear => Ok(None),
        MilestoneChoice::Set(milestone) => Ok(Some(milestone)),
        MilestoneChoice::Create(title) => create_milestone(repository, &title)
            .await
            .map(Some)
            .map_err(|error| error.to_string()),
    }
}

fn start_reviewer_action(
    item: WorkItem,
    action: ReviewerAction,
    reviewers: Vec<String>,
    config: Config,
    store: SnapshotStore,
    tx: UnboundedSender<AppMsg>,
) {
    tokio::spawn(async move {
        let item_id = item.id.clone();
        let result = match item.number {
            Some(number) => match action {
                ReviewerAction::Request => {
                    request_pull_request_reviewers(&item.repo, number, &reviewers)
                        .await
                        .map_err(|error| error.to_string())
                }
                ReviewerAction::Remove => {
                    remove_pull_request_reviewers(&item.repo, number, &reviewers)
                        .await
                        .map_err(|error| error.to_string())
                }
            },
            None => Err("selected item has no pull request number".to_string()),
        };
        let should_refresh = result.is_ok();
        let _ = tx.send(AppMsg::ReviewerActionFinished {
            item_id,
            action,
            reviewers,
            result,
        });

        if should_refresh {
            let _ = tx.send(AppMsg::RefreshStarted {
                scope: RefreshScope::Full,
            });
            let sections = with_background_github_priority(refresh_dashboard(&config)).await;
            let mut save_error = None;
            for section in &sections {
                if section.error.is_some() {
                    continue;
                }
                if let Err(error) = store.save_section(section) {
                    let message = error.to_string();
                    warn!(error = %message, "failed to save refreshed snapshot after reviewer action");
                    save_error = Some(message);
                    break;
                }
            }
            let _ = tx.send(AppMsg::RefreshFinished {
                sections,
                save_error,
            });
        }
    });
}

fn start_assignee_update(
    item: WorkItem,
    action: AssigneeAction,
    assignees: Vec<String>,
    tx: UnboundedSender<AppMsg>,
) {
    tokio::spawn(async move {
        let item_id = item.id.clone();
        let result = match item.number {
            Some(number) => {
                update_issue_assignees(&item.repo, number, item.kind, action, &assignees)
                    .await
                    .map_err(|error| error.to_string())
            }
            None => Err("selected item has no issue or pull request number".to_string()),
        };
        let _ = tx.send(AppMsg::AssigneesUpdated {
            item_id,
            action,
            result,
        });
    });
}

#[cfg(test)]
fn handle_key(
    app: &mut AppState,
    key: KeyEvent,
    config: &Config,
    store: &SnapshotStore,
    tx: &UnboundedSender<AppMsg>,
) -> bool {
    handle_key_in_area(app, key, config, store, tx, None)
}

#[cfg(test)]
fn handle_key_in_area(
    app: &mut AppState,
    key: KeyEvent,
    config: &Config,
    store: &SnapshotStore,
    tx: &UnboundedSender<AppMsg>,
    area: Option<Rect>,
) -> bool {
    let mut config = config.clone();
    let paths = test_key_paths();
    handle_key_in_area_mut(app, key, &mut config, &paths, store, tx, area)
}

#[cfg(test)]
fn test_key_paths() -> Paths {
    let root = std::path::PathBuf::from("/tmp/ghr-test-key");
    Paths {
        config_path: root.join("config.toml"),
        db_path: root.join("ghr.db"),
        log_path: root.join("ghr.log"),
        state_path: root.join("state.toml"),
        root,
    }
}

fn handle_key_in_area_mut(
    app: &mut AppState,
    key: KeyEvent,
    config: &mut Config,
    paths: &Paths,
    store: &SnapshotStore,
    tx: &UnboundedSender<AppMsg>,
    area: Option<Rect>,
) -> bool {
    app.command_palette_key = normalized_command_palette_key(&config.defaults.command_palette_key);

    if is_ctrl_c_key(key) {
        return true;
    }

    if app.setup_dialog.is_some() {
        match key.code {
            KeyCode::Char('q') => return true,
            KeyCode::Esc | KeyCode::Enter => app.dismiss_setup_dialog(),
            _ => {}
        }
        return false;
    }

    if let Some(dialog) = app.startup_dialog {
        match (dialog, key.code) {
            (StartupDialog::Initializing, _) => {}
            (StartupDialog::Ready, KeyCode::Esc | KeyCode::Enter | KeyCode::Char('q')) => {
                app.dismiss_startup_dialog()
            }
            (StartupDialog::Ready, KeyCode::Char('?')) => {
                app.dismiss_startup_dialog();
                app.show_help_dialog();
            }
            _ => {}
        }
        return false;
    }

    if app.message_dialog.is_some() {
        let retryable = app
            .message_dialog
            .as_ref()
            .is_some_and(|dialog| dialog.kind == MessageDialogKind::RetryableError);
        match key.code {
            KeyCode::Esc if retryable => app.dismiss_retryable_message_dialog(false),
            KeyCode::Enter | KeyCode::Char('q') if retryable => {
                app.dismiss_retryable_message_dialog(true)
            }
            KeyCode::Esc | KeyCode::Enter | KeyCode::Char('q') => app.dismiss_message_dialog(),
            _ => {}
        }
        return false;
    }

    if app.command_palette.is_some() {
        return app.handle_command_palette_key(key, config, paths, store, tx, area);
    }

    if app.project_switcher.is_some() {
        app.handle_project_switcher_key(key);
        return false;
    }

    if app.top_menu_switcher.is_some() {
        app.handle_top_menu_switcher_key(key);
        return false;
    }

    if app.recent_items_dialog.is_some() {
        app.handle_recent_items_key(key);
        return false;
    }

    if app.saved_search_dialog.is_some() {
        app.handle_saved_search_key(key, config, tx);
        return false;
    }

    if app.save_search_dialog.is_some() {
        app.handle_save_search_key(key, config, paths);
        return false;
    }

    if app.project_add_dialog.is_some() {
        app.handle_project_add_key(key, config, paths, store, tx);
        return false;
    }

    if app.project_remove_dialog.is_some() {
        app.handle_project_remove_key(key, config, paths);
        return false;
    }

    if app.cache_clear_dialog.is_some() {
        app.handle_cache_clear_key(key, store);
        return false;
    }

    if should_open_command_palette(app, key) {
        app.show_command_palette();
        return false;
    }

    if app.comment_dialog.is_some() {
        if editor_save_draft_key(key) {
            app.save_active_comment_draft(store, DraftSaveTrigger::Manual, Instant::now());
        } else {
            app.handle_comment_dialog_key_with_store(key, Some(store), tx, area);
        }
        return false;
    }

    if app.label_dialog.is_some() {
        app.handle_label_dialog_key(key, tx);
        return false;
    }

    if app.issue_dialog.is_some() {
        if editor_save_draft_key(key) {
            app.save_active_issue_draft(store, DraftSaveTrigger::Manual, Instant::now());
        } else {
            app.handle_issue_dialog_key_with_store(key, Some(store), tx, area);
        }
        return false;
    }

    if app.pr_create_dialog.is_some() {
        if editor_save_draft_key(key) {
            app.save_active_pr_create_draft(store, DraftSaveTrigger::Manual, Instant::now());
        } else {
            app.handle_pr_create_dialog_key_with_store(key, Some(store), tx, area);
        }
        return false;
    }

    if app.reaction_dialog.is_some() {
        app.handle_reaction_dialog_key(key, tx);
        return false;
    }

    if app.review_submit_dialog.is_some() {
        app.handle_review_submit_dialog_key(key, tx, area);
        return false;
    }

    if app.item_edit_dialog.is_some() {
        app.handle_item_edit_dialog_key(key);
        return false;
    }

    if app.pr_action_dialog.is_some() {
        app.handle_pr_action_dialog_key(key, config, store, tx);
        return false;
    }

    if app.milestone_dialog.is_some() {
        app.handle_milestone_dialog_key(key, config, store, tx);
        return false;
    }

    if app.assignee_dialog.is_some() {
        app.handle_assignee_dialog_key(key, tx);
        return false;
    }

    if app.reviewer_dialog.is_some() {
        app.handle_reviewer_dialog_key(key, config, store, tx);
        return false;
    }

    if app.comment_search_active {
        app.handle_comment_search_key(key, area);
        return false;
    }

    if app.filter_input_active {
        app.handle_filter_input_key(key, config, tx);
        return false;
    }

    if app.global_search_active {
        app.handle_global_search_key(key, config, tx);
        return false;
    }

    if app.help_dialog {
        match key.code {
            KeyCode::Esc | KeyCode::Enter | KeyCode::Char('?') | KeyCode::Char('q') => {
                app.dismiss_help_dialog()
            }
            _ => {}
        }
        return false;
    }

    if app.search_active {
        match key.code {
            KeyCode::Esc => app.clear_search(),
            KeyCode::Enter => app.search_active = false,
            KeyCode::Backspace => app.pop_search_char(),
            KeyCode::Char(value) => app.push_search_char(value),
            _ => {}
        }
        return false;
    }

    if handle_global_focus_key(app, key) {
        return false;
    }
    if handle_diff_focus_toggle_key(app, key) {
        return false;
    }
    if handle_list_details_focus_toggle_key(app, key) {
        return false;
    }
    if handle_mouse_or_mark_key(app, key) {
        return false;
    }
    if is_diff_key(key) {
        app.show_diff();
        return false;
    }
    if is_ctrl_d_key(key) {
        app.discard_pending_review(tx);
        return false;
    }

    match key.code {
        KeyCode::Esc if app.details_mode == DetailsMode::Diff => {
            app.leave_diff();
            return false;
        }
        KeyCode::Char('q') if app.details_mode == DetailsMode::Diff => {
            app.leave_diff();
            return false;
        }
        KeyCode::Char('i') if app.details_mode == DetailsMode::Diff => {
            app.toggle_diff_inline_comments();
            return false;
        }
        KeyCode::Char('q') => return true,
        KeyCode::Char('?') => app.show_help_dialog(),
        KeyCode::Char('r') => trigger_refresh(app, config, store, tx),
        KeyCode::Char('[') if key.modifiers.contains(KeyModifiers::ALT) => {
            start_section_page_load(app, config, store, tx, -1)
        }
        KeyCode::Char(']') if key.modifiers.contains(KeyModifiers::ALT) => {
            start_section_page_load(app, config, store, tx, 1)
        }
        KeyCode::Char('S') => app.start_global_search_input_with_store(Some(store), Some(tx)),
        KeyCode::Char('f') => app.start_filter_input(),
        KeyCode::Tab => app.move_focused_tab_group(1),
        KeyCode::BackTab => app.move_focused_tab_group(-1),
        KeyCode::Char('o') => app.open_selected(),
        _ if is_ignore_key(key) => app.ignore_current_item(),
        KeyCode::Char('T') => app.start_item_edit_dialog(),
        _ => {}
    }

    match app.focus {
        FocusTarget::Ghr => match key.code {
            KeyCode::Right | KeyCode::Char('l') | KeyCode::Char(']') => app.move_view(1),
            KeyCode::Left | KeyCode::Char('h') | KeyCode::Char('[') => app.move_view(-1),
            KeyCode::Down | KeyCode::Char('j') | KeyCode::Char('n') | KeyCode::Enter => {
                app.focus_sections()
            }
            KeyCode::Esc => app.focus_list(),
            _ => {}
        },
        FocusTarget::Sections => match key.code {
            KeyCode::Right | KeyCode::Char('l') | KeyCode::Char(']') => app.move_section(1),
            KeyCode::Left | KeyCode::Char('h') | KeyCode::Char('[') => app.move_section(-1),
            KeyCode::Up | KeyCode::Char('k') | KeyCode::Char('p') => app.focus_ghr(),
            KeyCode::Down | KeyCode::Char('j') | KeyCode::Char('n') | KeyCode::Enter => {
                app.focus_list()
            }
            KeyCode::Esc => app.focus_list(),
            _ => {}
        },
        FocusTarget::List if app.details_mode == DetailsMode::Diff => {
            handle_diff_file_list_key(app, key, config, area, store, tx)
        }
        FocusTarget::List => match key.code {
            KeyCode::Esc if !app.search_query.is_empty() => app.clear_search(),
            KeyCode::Esc if app.is_global_search_results_view() => {
                app.leave_global_search_results()
            }
            KeyCode::Esc
                if app
                    .current_section()
                    .is_some_and(|section| app.has_active_section_filter(&section.key)) =>
            {
                start_filtered_section_load(app, config, tx, None)
            }
            KeyCode::Esc => {}
            KeyCode::Char('/') => {
                if app.current_section().is_some_and(|section| {
                    matches!(
                        section.kind,
                        SectionKind::PullRequests | SectionKind::Issues
                    )
                }) {
                    app.start_global_search_input_with_store(Some(store), Some(tx));
                } else {
                    app.start_search();
                }
            }
            KeyCode::Down | KeyCode::Char('j') | KeyCode::Char('n') => {
                app.move_selection(1);
            }
            KeyCode::Up | KeyCode::Char('k') | KeyCode::Char('p') => {
                if app.current_selected_position() == 0 {
                    app.focus_sections();
                } else {
                    app.move_selection(-1);
                }
            }
            KeyCode::PageDown | KeyCode::Char('d') => {
                app.move_selection(list_page_delta(app, area, 1));
            }
            KeyCode::PageUp | KeyCode::Char('u') => {
                app.move_selection(list_page_delta(app, area, -1));
            }
            KeyCode::Char('[') => start_section_page_load(app, config, store, tx, -1),
            KeyCode::Char(']') => start_section_page_load(app, config, store, tx, 1),
            KeyCode::Char('g') => {
                app.set_selection(0);
            }
            KeyCode::Char('G') => {
                app.select_last();
            }
            KeyCode::Char('M') => app.start_pr_action_dialog(PrAction::Merge),
            KeyCode::Char('C') => app.start_close_or_reopen_dialog(),
            KeyCode::Char('A') => app.start_review_submit_dialog(PullRequestReviewEvent::Approve),
            KeyCode::Char('s') => app.start_review_submit_dialog(PullRequestReviewEvent::Comment),
            KeyCode::Char('D') => app.start_pr_draft_ready_dialog(),
            KeyCode::Char('E') => app.start_pr_action_dialog(PrAction::EnableAutoMerge),
            KeyCode::Char('O') => app.start_pr_action_dialog(PrAction::DisableAutoMerge),
            KeyCode::Char('U') => app.start_pr_action_dialog(PrAction::UpdateBranch),
            KeyCode::Char('X') => app.start_pr_checkout_dialog(config),
            KeyCode::Char('F') => app.start_pr_action_dialog(PrAction::RerunFailedChecks),
            KeyCode::Char('t') => app.start_milestone_dialog(tx),
            KeyCode::Char('P') => {
                app.start_reviewer_dialog_with_store(ReviewerAction::Request, Some(store), Some(tx))
            }
            KeyCode::Char('Y') => {
                app.start_reviewer_dialog_with_store(ReviewerAction::Remove, Some(store), Some(tx))
            }
            KeyCode::Char('Z') => app.start_pr_draft_ready_dialog(),
            KeyCode::Char('a') => app.start_new_comment_dialog(),
            KeyCode::Char('L') => app.start_add_label_dialog_with_store(Some(store), Some(tx)),
            KeyCode::Char('N') => app.start_new_issue_or_pull_request_dialog(config),
            _ if is_assignee_assign_key(key) => {
                app.start_assignee_dialog_with_store(AssigneeAction::Assign, Some(store), Some(tx))
            }
            KeyCode::Char('-') => app.start_assignee_dialog_with_store(
                AssigneeAction::Unassign,
                Some(store),
                Some(tx),
            ),
            _ if is_reaction_key(key) => app.start_item_reaction_dialog(),
            KeyCode::Enter => {
                app.focus_details();
                app.mark_current_notification_read(store, tx);
            }
            _ => {}
        },
        FocusTarget::Details => match key.code {
            KeyCode::Esc
                if app.details_mode == DetailsMode::Conversation
                    && !app.comment_search_query.is_empty() =>
            {
                app.clear_comment_search()
            }
            KeyCode::Esc => app.focus_list(),
            KeyCode::Char('/') if app.details_mode == DetailsMode::Conversation => {
                app.start_comment_search()
            }
            KeyCode::Char('M') => app.start_pr_action_dialog(PrAction::Merge),
            KeyCode::Char('C') => app.start_close_or_reopen_dialog(),
            KeyCode::Char('A') => app.start_review_submit_dialog(PullRequestReviewEvent::Approve),
            KeyCode::Char('s') => app.start_review_submit_dialog(PullRequestReviewEvent::Comment),
            KeyCode::Char('D') => app.start_pr_draft_ready_dialog(),
            KeyCode::Char('E') => app.start_pr_action_dialog(PrAction::EnableAutoMerge),
            KeyCode::Char('O') => app.start_pr_action_dialog(PrAction::DisableAutoMerge),
            KeyCode::Char('U') => app.start_pr_action_dialog(PrAction::UpdateBranch),
            KeyCode::Char('X') => app.start_pr_checkout_dialog(config),
            KeyCode::Char('L') if app.details_mode == DetailsMode::Conversation => {
                app.start_add_label_dialog_with_store(Some(store), Some(tx))
            }
            KeyCode::Char('N') => app.start_new_issue_or_pull_request_dialog(config),
            KeyCode::Char('F') => app.start_pr_action_dialog(PrAction::RerunFailedChecks),
            KeyCode::Char('t') => app.start_milestone_dialog(tx),
            _ if is_assignee_assign_key(key) => {
                app.start_assignee_dialog_with_store(AssigneeAction::Assign, Some(store), Some(tx))
            }
            KeyCode::Char('-') => app.start_assignee_dialog_with_store(
                AssigneeAction::Unassign,
                Some(store),
                Some(tx),
            ),
            KeyCode::Char('P') => {
                app.start_reviewer_dialog_with_store(ReviewerAction::Request, Some(store), Some(tx))
            }
            KeyCode::Char('Y') => {
                app.start_reviewer_dialog_with_store(ReviewerAction::Remove, Some(store), Some(tx))
            }
            KeyCode::Char('Z') => app.start_pr_draft_ready_dialog(),
            KeyCode::Char('c') if app.details_mode == DetailsMode::Diff => {
                app.start_review_comment_dialog()
            }
            KeyCode::Char('a') if app.details_mode == DetailsMode::Diff => {
                app.start_new_comment_dialog()
            }
            KeyCode::Char('c') | KeyCode::Char('a')
                if app.details_mode == DetailsMode::Conversation =>
            {
                app.start_new_comment_dialog()
            }
            KeyCode::Char('R') if app.details_mode == DetailsMode::Conversation => {
                app.start_reply_to_selected_comment()
            }
            _ if app.details_mode == DetailsMode::Conversation && is_reaction_key(key) => {
                app.start_keyboard_reaction_dialog(area)
            }
            KeyCode::Char('e') if app.details_mode == DetailsMode::Conversation => {
                app.start_edit_selected_comment_dialog()
            }
            KeyCode::Char('n') => app.move_comment_in_view(1, area),
            KeyCode::Char('p') => app.move_comment_in_view(-1, area),
            KeyCode::Char('h') if app.details_mode == DetailsMode::Diff => {
                app.page_diff_lines(1, area)
            }
            KeyCode::Char('l') if app.details_mode == DetailsMode::Diff => {
                app.page_diff_lines(-1, area)
            }
            KeyCode::Char(']') if app.details_mode == DetailsMode::Diff => app.move_diff_file(1),
            KeyCode::Char('[') if app.details_mode == DetailsMode::Diff => app.move_diff_file(-1),
            KeyCode::Down | KeyCode::Char('j') if app.details_mode == DetailsMode::Diff => {
                app.move_diff_line(1, area)
            }
            KeyCode::Up | KeyCode::Char('k') if app.details_mode == DetailsMode::Diff => {
                app.move_diff_line(-1, area)
            }
            KeyCode::PageDown | KeyCode::Char('d') if app.details_mode == DetailsMode::Diff => {
                app.page_diff_lines(1, area)
            }
            KeyCode::PageUp | KeyCode::Char('u') if app.details_mode == DetailsMode::Diff => {
                app.page_diff_lines(-1, area)
            }
            KeyCode::Char('g') if app.details_mode == DetailsMode::Diff => {
                app.scroll_diff_details_to_top(area)
            }
            KeyCode::Char('G') if app.details_mode == DetailsMode::Diff => {
                app.scroll_diff_details_to_bottom(area)
            }
            KeyCode::Char('e') if app.details_mode == DetailsMode::Diff => app.end_diff_mark(),
            KeyCode::Enter if app.details_mode == DetailsMode::Conversation => {
                app.toggle_selected_comment_expanded()
            }
            KeyCode::Down | KeyCode::Char('j') => app.scroll_details(1),
            KeyCode::Up | KeyCode::Char('k') => app.scroll_details(-1),
            KeyCode::PageDown | KeyCode::Char('d') => app.scroll_details(8),
            KeyCode::PageUp | KeyCode::Char('u') => app.scroll_details(-8),
            KeyCode::Char('g') => app.scroll_conversation_details_to_top(),
            KeyCode::Char('G') => app.scroll_conversation_details_to_bottom(area),
            _ => {}
        },
    }

    false
}

fn handle_global_focus_key(app: &mut AppState, key: KeyEvent) -> bool {
    match key.code {
        KeyCode::Char('1') => app.focus_ghr(),
        KeyCode::Char('2') => app.focus_sections(),
        KeyCode::Char('3') => app.focus_primary_list(),
        KeyCode::Char('4') => app.focus_details(),
        _ => return false,
    }
    true
}

fn handle_diff_focus_toggle_key(app: &mut AppState, key: KeyEvent) -> bool {
    if app.details_mode != DetailsMode::Diff {
        return false;
    }
    if !matches!(key.code, KeyCode::Tab | KeyCode::BackTab) {
        return false;
    }

    match app.focus {
        FocusTarget::List => app.focus_details(),
        FocusTarget::Details => app.focus_list(),
        _ => return false,
    }
    true
}

fn handle_list_details_focus_toggle_key(app: &mut AppState, key: KeyEvent) -> bool {
    if app.details_mode != DetailsMode::Conversation {
        return false;
    }
    if !matches!(key.code, KeyCode::Tab | KeyCode::BackTab) {
        return false;
    }

    match app.focus {
        FocusTarget::List => {
            app.focus_details();
            true
        }
        FocusTarget::Details => {
            app.focus_list();
            true
        }
        _ => false,
    }
}

fn handle_mouse_or_mark_key(app: &mut AppState, key: KeyEvent) -> bool {
    if !matches!(key.code, KeyCode::Char('m')) {
        return false;
    }

    if !app.mouse_capture_enabled {
        app.toggle_mouse_capture();
    } else if app.details_mode == DetailsMode::Diff {
        if app.focus == FocusTarget::Details {
            app.begin_diff_mark();
        } else {
            app.status = "mark diff lines from Details; press 4 or enter first".to_string();
        }
    } else {
        app.toggle_mouse_capture();
    }
    true
}

fn handle_diff_file_list_key(
    app: &mut AppState,
    key: KeyEvent,
    config: &Config,
    area: Option<Rect>,
    store: &SnapshotStore,
    tx: &UnboundedSender<AppMsg>,
) {
    match key.code {
        KeyCode::Esc => app.leave_diff(),
        KeyCode::Char('c') => app.start_review_comment_dialog(),
        KeyCode::Char('a') => app.start_new_comment_dialog(),
        KeyCode::Char('P') => {
            app.start_reviewer_dialog_with_store(ReviewerAction::Request, Some(store), Some(tx))
        }
        KeyCode::Char('Y') => {
            app.start_reviewer_dialog_with_store(ReviewerAction::Remove, Some(store), Some(tx))
        }
        KeyCode::Down | KeyCode::Char('j') => app.move_diff_file(1),
        KeyCode::Up | KeyCode::Char('k') => app.move_diff_file(-1),
        KeyCode::PageDown | KeyCode::Char('d') => {
            app.move_diff_file(diff_file_page_delta(app, area, 1));
        }
        KeyCode::PageUp | KeyCode::Char('u') => {
            app.move_diff_file(diff_file_page_delta(app, area, -1));
        }
        KeyCode::Char('h') => app.page_diff_lines(1, area),
        KeyCode::Char('l') => app.page_diff_lines(-1, area),
        KeyCode::Char('g') => {
            if let Some(order) = app.current_diff_file_order() {
                if let Some(file_index) = order.first() {
                    app.select_diff_file(*file_index);
                } else {
                    app.status = "no diff files".to_string();
                }
            } else {
                app.status = "diff still loading".to_string();
            }
        }
        KeyCode::Char('G') => {
            if let Some(order) = app.current_diff_file_order() {
                if let Some(file_index) = order.last() {
                    app.select_diff_file(*file_index);
                } else {
                    app.status = "no diff files".to_string();
                }
            } else {
                app.status = "diff still loading".to_string();
            }
        }
        KeyCode::Char('[') => app.move_diff_file(-1),
        KeyCode::Char(']') => app.move_diff_file(1),
        KeyCode::Char('M') => app.start_pr_action_dialog(PrAction::Merge),
        KeyCode::Char('C') => app.start_close_or_reopen_dialog(),
        KeyCode::Char('A') => app.start_review_submit_dialog(PullRequestReviewEvent::Approve),
        KeyCode::Char('s') => app.start_review_submit_dialog(PullRequestReviewEvent::Comment),
        KeyCode::Char('D') => app.start_pr_draft_ready_dialog(),
        KeyCode::Char('E') => app.start_pr_action_dialog(PrAction::EnableAutoMerge),
        KeyCode::Char('O') => app.start_pr_action_dialog(PrAction::DisableAutoMerge),
        KeyCode::Char('U') => app.start_pr_action_dialog(PrAction::UpdateBranch),
        KeyCode::Char('X') => app.start_pr_checkout_dialog(config),
        KeyCode::Char('F') => app.start_pr_action_dialog(PrAction::RerunFailedChecks),
        KeyCode::Char('t') => app.start_milestone_dialog(tx),
        _ if is_assignee_assign_key(key) => {
            app.start_assignee_dialog_with_store(AssigneeAction::Assign, Some(store), Some(tx))
        }
        KeyCode::Char('-') => {
            app.start_assignee_dialog_with_store(AssigneeAction::Unassign, Some(store), Some(tx))
        }
        KeyCode::Char('Z') => app.start_pr_draft_ready_dialog(),
        KeyCode::Enter => app.focus_details(),
        _ => {}
    }
}

fn trigger_refresh(
    app: &mut AppState,
    config: &Config,
    store: &SnapshotStore,
    tx: &UnboundedSender<AppMsg>,
) {
    if app.refreshing {
        app.status = "refresh already running".to_string();
    } else {
        start_refresh(
            config.clone(),
            store.clone(),
            tx.clone(),
            RefreshPriority::User,
            RefreshScope::Full,
        );
    }
}

fn refresh_started_status(scope: &RefreshScope) -> String {
    match scope {
        RefreshScope::Full => "refreshing from GitHub".to_string(),
        RefreshScope::View(view) => format!("refreshing {}", refresh_scope_view_label(view)),
    }
}

fn refresh_finished_status(scope: &RefreshScope) -> String {
    match scope {
        RefreshScope::Full => "latest".to_string(),
        RefreshScope::View(_) => "current view latest".to_string(),
    }
}

fn refresh_scope_view_label(view: &str) -> String {
    match view {
        "notifications" => "inbox".to_string(),
        "pull_requests" => "pull requests".to_string(),
        "issues" => "issues".to_string(),
        view if view.starts_with("repo:") => format!("repo {}", view.trim_start_matches("repo:")),
        _ => "current view".to_string(),
    }
}

fn save_ui_state(app: &mut AppState, paths: &Paths) {
    app.sync_recent_details_visit(Instant::now());
    if let Err(error) = app.ui_state().save(&paths.state_path) {
        let message = error.to_string();
        warn!(error = %message, "failed to save ui state");
        app.status = format!("layout save failed: {message}");
    }
}

#[cfg(test)]
fn handle_mouse(app: &mut AppState, mouse: MouseEvent, area: Rect) -> bool {
    handle_mouse_with_sync(app, mouse, area, None, None)
}

fn handle_mouse_with_sync(
    app: &mut AppState,
    mouse: MouseEvent,
    area: Rect,
    store: Option<&SnapshotStore>,
    tx: Option<&UnboundedSender<AppMsg>>,
) -> bool {
    if !app.mouse_capture_enabled {
        return false;
    }
    if app.setup_dialog.is_some() {
        return false;
    }
    if let Some(dialog) = app.startup_dialog {
        return handle_startup_dialog_mouse(app, dialog, mouse, area);
    }
    if app.help_dialog {
        return false;
    }
    if app.message_dialog.is_some() {
        return false;
    }
    if app.command_palette.is_some()
        || app.project_switcher.is_some()
        || app.top_menu_switcher.is_some()
        || app.recent_items_dialog.is_some()
        || app.saved_search_dialog.is_some()
        || app.save_search_dialog.is_some()
        || app.project_add_dialog.is_some()
        || app.project_remove_dialog.is_some()
        || app.cache_clear_dialog.is_some()
    {
        return false;
    }
    if let Some(dialog) = &app.pr_action_dialog {
        if matches!(mouse.kind, MouseEventKind::Down(MouseButton::Left))
            && let Some(url) = pr_action_dialog_link_at(dialog, area, mouse.column, mouse.row)
        {
            app.open_url(&url);
        }
        return false;
    }
    if app.label_dialog.is_some() {
        return false;
    }
    if app.issue_dialog.is_some() {
        handle_issue_dialog_mouse(app, mouse, area, store);
        return false;
    }
    if app.pr_create_dialog.is_some() {
        handle_pr_create_dialog_mouse(app, mouse, area, store);
        return false;
    }
    if app.reaction_dialog.is_some() {
        return false;
    }
    if app.item_edit_dialog.is_some() {
        return false;
    }
    if app.review_submit_dialog.is_some() {
        handle_review_submit_dialog_mouse(app, mouse, area);
        return false;
    }
    if app.milestone_dialog.is_some() {
        return false;
    }
    if app.global_search_active || app.filter_input_active || app.comment_search_active {
        return false;
    }
    if let Some(dialog) = &app.comment_dialog {
        handle_comment_dialog_mouse(app, dialog.clone(), mouse, area, store);
        return false;
    }

    let page = page_areas(area);
    let body_area = page[2];
    let body = body_areas_with_ratio(body_area, app.list_width_percent);
    let details_area = body[1];
    let layout = MouseLayout {
        view_tabs: page[0],
        section_tabs: page[1],
        table: body[0],
        details: details_area,
    };

    match mouse.kind {
        MouseEventKind::Down(MouseButton::Left) => {
            debug!(
                column = mouse.column,
                row = mouse.row,
                view = %app.active_view,
                focus = ?app.focus,
                mode = ?app.details_mode,
                "mouse left click"
            );
            if splitter_contains(
                body_area,
                layout.table,
                layout.details,
                mouse.column,
                mouse.row,
            ) {
                debug!(
                    column = mouse.column,
                    row = mouse.row,
                    target = "splitter",
                    "mouse click handled"
                );
                app.start_split_drag();
                return false;
            }
            handle_left_click(app, mouse, layout, store, tx);
        }
        MouseEventKind::Drag(MouseButton::Left) if app.dragging_split => {
            app.update_split_drag(body_area, mouse.column);
        }
        MouseEventKind::Up(MouseButton::Left) if app.dragging_split => {
            app.update_split_drag(body_area, mouse.column);
            return app.finish_split_drag();
        }
        MouseEventKind::Drag(MouseButton::Left) if app.details_text_drag.is_some() => {
            handle_details_text_drag(app, mouse, layout.details);
        }
        MouseEventKind::Up(MouseButton::Left) if app.details_text_drag.is_some() => {
            finish_details_text_drag(app, mouse, layout.details);
        }
        MouseEventKind::ScrollDown if rect_contains(layout.table, mouse.column, mouse.row) => {
            handle_list_scroll(app, layout.table, mouse_list_scroll_delta(app, 1));
        }
        MouseEventKind::ScrollUp if rect_contains(layout.table, mouse.column, mouse.row) => {
            handle_list_scroll(app, layout.table, mouse_list_scroll_delta(app, -1));
        }
        MouseEventKind::ScrollDown if rect_contains(layout.details, mouse.column, mouse.row) => {
            handle_details_scroll(app, layout.details, MOUSE_DETAILS_SCROLL_LINES as i16);
        }
        MouseEventKind::ScrollUp if rect_contains(layout.details, mouse.column, mouse.row) => {
            handle_details_scroll(app, layout.details, -(MOUSE_DETAILS_SCROLL_LINES as i16));
        }
        MouseEventKind::Moved if rect_contains(layout.details, mouse.column, mouse.row) => {
            handle_details_hover(app, mouse, layout.details);
        }
        _ => {}
    }

    false
}

fn handle_startup_dialog_mouse(
    app: &mut AppState,
    dialog: StartupDialog,
    mouse: MouseEvent,
    area: Rect,
) -> bool {
    if !matches!(dialog, StartupDialog::Ready)
        || !matches!(mouse.kind, MouseEventKind::Down(MouseButton::Left))
    {
        return false;
    }

    let dialog_area = startup_dialog_area(dialog, area);
    if rect_contains(startup_dialog_ok_area(dialog_area), mouse.column, mouse.row) {
        app.dismiss_startup_dialog();
        return true;
    }

    false
}

fn handle_comment_dialog_mouse(
    app: &mut AppState,
    dialog: CommentDialog,
    mouse: MouseEvent,
    area: Rect,
    store: Option<&SnapshotStore>,
) {
    let dialog_area = comment_dialog_area(&dialog, area);
    if matches!(mouse.kind, MouseEventKind::Down(MouseButton::Left))
        && modal_footer_area(area, dialog_area)
            .is_some_and(|footer| rect_contains(footer, mouse.column, mouse.row))
    {
        if let Some(store) = store {
            app.save_active_comment_draft(store, DraftSaveTrigger::Manual, Instant::now());
        } else {
            app.status = "draft store unavailable".to_string();
        }
        return;
    }
    if !rect_contains(dialog_area, mouse.column, mouse.row) {
        return;
    }

    match mouse.kind {
        MouseEventKind::ScrollDown => {
            app.scroll_comment_dialog(MOUSE_COMMENT_SCROLL_LINES as i16, Some(area));
        }
        MouseEventKind::ScrollUp => {
            app.scroll_comment_dialog(-(MOUSE_COMMENT_SCROLL_LINES as i16), Some(area));
        }
        MouseEventKind::Down(MouseButton::Left) => {
            let inner = block_inner(dialog_area);
            if !rect_contains(inner, mouse.column, mouse.row) {
                return;
            }
            let line = usize::from(dialog.scroll).saturating_add(usize::from(mouse.row - inner.y));
            let column = mouse.column.saturating_sub(inner.x);
            if let Some(active) = &mut app.comment_dialog {
                let cursor = comment_dialog_cursor_for_position(
                    active.body.text(),
                    inner.width.max(1),
                    line,
                    column,
                );
                active.body.set_cursor_byte(cursor);
            }
            app.scroll_comment_dialog_to_cursor_in_area(Some(area));
            app.status = "comment cursor moved".to_string();
        }
        _ => {}
    }
}

fn handle_review_submit_dialog_mouse(app: &mut AppState, mouse: MouseEvent, area: Rect) {
    let Some(dialog) = app.review_submit_dialog.clone() else {
        return;
    };
    let dialog_area = review_submit_dialog_area(&dialog, area);
    if !rect_contains(dialog_area, mouse.column, mouse.row) {
        return;
    }

    match mouse.kind {
        MouseEventKind::ScrollDown => {
            app.scroll_review_submit_dialog(MOUSE_COMMENT_SCROLL_LINES as i16, Some(area));
        }
        MouseEventKind::ScrollUp => {
            app.scroll_review_submit_dialog(-(MOUSE_COMMENT_SCROLL_LINES as i16), Some(area));
        }
        MouseEventKind::Down(MouseButton::Left) => {
            let inner = block_inner(dialog_area);
            let header_height = 3_u16.min(inner.height);
            let editor_area = Rect::new(
                inner.x,
                inner.y.saturating_add(header_height),
                inner.width,
                inner.height.saturating_sub(header_height),
            );
            if !rect_contains(editor_area, mouse.column, mouse.row) {
                return;
            }
            let line =
                usize::from(dialog.scroll).saturating_add(usize::from(mouse.row - editor_area.y));
            let column = mouse.column.saturating_sub(editor_area.x);
            if let Some(active) = &mut app.review_submit_dialog {
                let cursor = comment_dialog_cursor_for_position(
                    active.body.text(),
                    editor_area.width.max(1),
                    line,
                    column,
                );
                active.body.set_cursor_byte(cursor);
            }
            app.scroll_review_submit_dialog_to_cursor_in_area(Some(area));
            app.status = "review summary cursor moved".to_string();
        }
        _ => {}
    }
}

fn handle_issue_dialog_mouse(
    app: &mut AppState,
    mouse: MouseEvent,
    area: Rect,
    store: Option<&SnapshotStore>,
) {
    let Some(dialog) = app.issue_dialog.clone() else {
        return;
    };
    let dialog_area = issue_dialog_area(area);
    if matches!(mouse.kind, MouseEventKind::Down(MouseButton::Left))
        && modal_footer_area(area, dialog_area)
            .is_some_and(|footer| rect_contains(footer, mouse.column, mouse.row))
    {
        if let Some(store) = store {
            app.save_active_issue_draft(store, DraftSaveTrigger::Manual, Instant::now());
        } else {
            app.status = "draft store unavailable".to_string();
        }
        return;
    }
    if !rect_contains(dialog_area, mouse.column, mouse.row) {
        return;
    }

    match mouse.kind {
        MouseEventKind::ScrollDown => {
            app.scroll_issue_dialog_body(MOUSE_COMMENT_SCROLL_LINES as i16, Some(area));
        }
        MouseEventKind::ScrollUp => {
            app.scroll_issue_dialog_body(-(MOUSE_COMMENT_SCROLL_LINES as i16), Some(area));
        }
        MouseEventKind::Down(MouseButton::Left) => {
            let inner = block_inner(dialog_area);
            if !rect_contains(inner, mouse.column, mouse.row) {
                return;
            }
            let row = mouse.row.saturating_sub(inner.y);
            if let Some(active) = &mut app.issue_dialog {
                match row {
                    0 => {
                        active.field = IssueDialogField::Repo;
                        let cursor = issue_dialog_mouse_input_cursor(
                            "Repo",
                            active.repo.text(),
                            inner,
                            mouse,
                        );
                        active.repo.set_cursor_byte(cursor);
                        app.status = "editing issue repo".to_string();
                    }
                    2 => {
                        active.field = IssueDialogField::Title;
                        let cursor = issue_dialog_mouse_input_cursor(
                            "Title",
                            active.title.text(),
                            inner,
                            mouse,
                        );
                        active.title.set_cursor_byte(cursor);
                        app.status = "editing issue title".to_string();
                    }
                    4 => {
                        active.field = IssueDialogField::Labels;
                        let cursor = issue_dialog_mouse_input_cursor(
                            "Labels",
                            active.labels.text(),
                            inner,
                            mouse,
                        );
                        active.labels.set_cursor_byte(cursor);
                        app.status = "editing issue labels".to_string();
                    }
                    6 => {
                        active.field = IssueDialogField::Body;
                        app.status = "editing issue body".to_string();
                    }
                    row if row >= 7 => {
                        active.field = IssueDialogField::Body;
                        let line = usize::from(dialog.body_scroll)
                            .saturating_add(usize::from(row.saturating_sub(7)));
                        let column = mouse.column.saturating_sub(inner.x);
                        let cursor = comment_dialog_cursor_for_position(
                            active.body.text(),
                            inner.width.max(1),
                            line,
                            column,
                        );
                        active.body.set_cursor_byte(cursor);
                        app.status = "editing issue body".to_string();
                    }
                    _ => {}
                }
            }
            app.scroll_issue_dialog_to_cursor_in_area(Some(area));
        }
        _ => {}
    }
}

fn handle_pr_create_dialog_mouse(
    app: &mut AppState,
    mouse: MouseEvent,
    area: Rect,
    store: Option<&SnapshotStore>,
) {
    let Some(dialog) = app.pr_create_dialog.clone() else {
        return;
    };
    let dialog_area = pr_create_dialog_area(area);
    if matches!(mouse.kind, MouseEventKind::Down(MouseButton::Left))
        && modal_footer_area(area, dialog_area)
            .is_some_and(|footer| rect_contains(footer, mouse.column, mouse.row))
    {
        if let Some(store) = store {
            app.save_active_pr_create_draft(store, DraftSaveTrigger::Manual, Instant::now());
        } else {
            app.status = "draft store unavailable".to_string();
        }
        return;
    }
    if !rect_contains(dialog_area, mouse.column, mouse.row) {
        return;
    }

    match mouse.kind {
        MouseEventKind::ScrollDown => {
            app.scroll_pr_create_dialog_body(MOUSE_COMMENT_SCROLL_LINES as i16, Some(area));
        }
        MouseEventKind::ScrollUp => {
            app.scroll_pr_create_dialog_body(-(MOUSE_COMMENT_SCROLL_LINES as i16), Some(area));
        }
        MouseEventKind::Down(MouseButton::Left) => {
            let inner = block_inner(dialog_area);
            if !rect_contains(inner, mouse.column, mouse.row) {
                return;
            }
            let row = mouse.row.saturating_sub(inner.y);
            if let Some(active) = &mut app.pr_create_dialog {
                match row {
                    4 => {
                        active.field = PrCreateField::Title;
                        let cursor = issue_dialog_mouse_input_cursor(
                            "Title",
                            active.title.text(),
                            inner,
                            mouse,
                        );
                        active.title.set_cursor_byte(cursor);
                        app.status = "editing pull request title".to_string();
                    }
                    6 => {
                        active.field = PrCreateField::Body;
                        app.status = "editing pull request body".to_string();
                    }
                    row if row >= 7 => {
                        active.field = PrCreateField::Body;
                        let line = usize::from(dialog.body_scroll)
                            .saturating_add(usize::from(row.saturating_sub(7)));
                        let column = mouse.column.saturating_sub(inner.x);
                        let cursor = comment_dialog_cursor_for_position(
                            active.body.text(),
                            inner.width.max(1),
                            line,
                            column,
                        );
                        active.body.set_cursor_byte(cursor);
                        app.status = "editing pull request body".to_string();
                    }
                    _ => {}
                }
            }
            app.scroll_pr_create_dialog_to_cursor_in_area(Some(area));
        }
        _ => {}
    }
}

fn issue_dialog_mouse_input_cursor(
    label: &'static str,
    value: &str,
    inner: Rect,
    mouse: MouseEvent,
) -> usize {
    let prefix_width =
        display_width(&issue_dialog_field_prefix(label)).min(usize::from(u16::MAX)) as u16;
    let input_start = inner.x.saturating_add(prefix_width);
    cursor_for_inline_column(value, mouse.column.saturating_sub(input_start))
}

#[derive(Debug, Clone, Copy)]
struct MouseLayout {
    view_tabs: Rect,
    section_tabs: Rect,
    table: Rect,
    details: Rect,
}

fn handle_left_click(
    app: &mut AppState,
    mouse: MouseEvent,
    layout: MouseLayout,
    store: Option<&SnapshotStore>,
    tx: Option<&UnboundedSender<AppMsg>>,
) {
    app.details_text_drag = None;
    app.details_text_selection = None;

    if let Some(view) = view_tab_at(app, layout.view_tabs, mouse.column, mouse.row) {
        let previous_view = app.active_view.clone();
        debug!(
            column = mouse.column,
            row = mouse.row,
            target = "view_tab",
            from = %previous_view,
            to = %view,
            "mouse click handled"
        );
        let restored = app.switch_view(view);
        app.search_active = false;
        app.comment_search_active = false;
        app.global_search_active = false;
        app.filter_input_active = false;
        if !restored {
            app.focus = FocusTarget::Ghr;
            app.status = "ghr focused".to_string();
        }
        return;
    }

    if let Some(section_index) = section_tab_at(app, layout.section_tabs, mouse.column, mouse.row) {
        debug!(
            column = mouse.column,
            row = mouse.row,
            target = "section_tab",
            section_index,
            "mouse click handled"
        );
        app.select_section(section_index);
        return;
    }

    if rect_contains(layout.table, mouse.column, mouse.row) {
        debug!(
            column = mouse.column,
            row = mouse.row,
            target = "table",
            "mouse click handled"
        );
        handle_table_click(app, mouse, layout.table, store, tx);
        return;
    }

    if !rect_contains(layout.details, mouse.column, mouse.row) {
        return;
    }

    let inner = block_inner(layout.details);
    if !rect_contains(inner, mouse.column, mouse.row) {
        return;
    }

    let document = build_details_document(app, inner.width);
    let line_index = app.details_scroll as usize + (mouse.row - inner.y) as usize;
    let column = mouse.column - inner.x;
    debug!(
        column = mouse.column,
        row = mouse.row,
        target = "details",
        details_line = line_index,
        details_column = column,
        "mouse click handled"
    );
    app.focus = FocusTarget::Details;
    app.search_active = false;
    app.comment_search_active = false;
    app.global_search_active = false;
    app.filter_input_active = false;

    if let Some(action) = document.action_at(line_index, column) {
        debug!(action = ?action, "details action clicked");
        app.handle_detail_action(action, store, tx);
        return;
    }
    let clicked_comment = document.comment_at(line_index);
    let clicked_description = document.description_at(line_index);
    if let Some(url) = document.link_at(line_index, column) {
        debug!(
            url = %url,
            comment = ?clicked_comment,
            description = clicked_description,
            "details link clicked"
        );
        if let Some(comment_index) = clicked_comment {
            app.select_comment(comment_index);
        } else if clicked_description {
            app.select_details_body_without_scroll();
        }
        app.open_url(&url);
        return;
    }
    if app.details_mode == DetailsMode::Diff
        && let Some(comment_indices) = document.inline_comment_marker_at(line_index)
    {
        debug!(comment_indices = ?comment_indices, "inline comment marker clicked");
        app.toggle_revealed_diff_inline_comments(comment_indices);
        return;
    }
    if app.details_mode == DetailsMode::Diff
        && let Some(diff_line) = document.diff_line_at(line_index)
    {
        debug!(line = ?diff_line, "diff line clicked");
        app.handle_diff_line_click(diff_line, None);
        return;
    }
    if document.lines.get(line_index).is_some()
        && let Some(item_id) = app.current_item().map(|item| item.id.clone())
    {
        app.details_text_drag = Some(DetailsTextDrag {
            item_id,
            start: DetailsTextPosition {
                line: line_index,
                column,
            },
        });
    }
    if let Some(comment_index) = clicked_comment {
        debug!(comment_index, "comment clicked");
        app.select_comment(comment_index);
    } else if clicked_description {
        debug!("description clicked");
        app.select_details_body_without_scroll();
    }
}

fn handle_details_text_drag(app: &mut AppState, mouse: MouseEvent, area: Rect) {
    let Some(drag) = app.details_text_drag.clone() else {
        return;
    };
    let Some(position) = details_text_position_from_mouse(app, mouse, area, true) else {
        return;
    };

    app.focus = FocusTarget::Details;
    app.search_active = false;
    app.comment_search_active = false;
    app.global_search_active = false;
    app.filter_input_active = false;
    app.details_text_selection = Some(DetailsTextSelection {
        item_id: drag.item_id,
        start: drag.start,
        end: position,
    });
    app.status = "selecting details text; release to copy".to_string();
}

fn finish_details_text_drag(app: &mut AppState, mouse: MouseEvent, area: Rect) {
    if let Some(position) = details_text_position_from_mouse(app, mouse, area, true)
        && let Some(selection) = &mut app.details_text_selection
    {
        selection.end = position;
    }
    app.details_text_drag = None;

    let Some(selection) = app.details_text_selection.clone() else {
        return;
    };
    let Some(item_id) = app.current_item().map(|item| item.id.as_str()) else {
        app.details_text_selection = None;
        return;
    };
    if selection.item_id != item_id {
        app.details_text_selection = None;
        return;
    }

    let inner = block_inner(area);
    let document = build_details_document(app, inner.width);
    let selected = selected_details_text(&document, &selection);
    if selected.trim().is_empty() {
        app.details_text_selection = None;
        app.status = "no details text selected".to_string();
        return;
    }

    match copy_text_to_clipboard(&selected) {
        Ok(()) => {
            app.status = "copied selected details text".to_string();
        }
        Err(error) => {
            app.status = format!("copy failed: {error}");
        }
    }
}

fn details_text_position_from_mouse(
    app: &AppState,
    mouse: MouseEvent,
    area: Rect,
    clamp: bool,
) -> Option<DetailsTextPosition> {
    let inner = block_inner(area);
    if inner.width == 0 || inner.height == 0 {
        return None;
    }

    let (row, column) = if clamp {
        let row = mouse.row.clamp(
            inner.y,
            inner.y.saturating_add(inner.height.saturating_sub(1)),
        );
        let column = mouse.column.clamp(
            inner.x,
            inner.x.saturating_add(inner.width.saturating_sub(1)),
        );
        (row, column)
    } else {
        if !rect_contains(inner, mouse.column, mouse.row) {
            return None;
        }
        (mouse.row, mouse.column)
    };

    let document = build_details_document(app, inner.width);
    if document.lines.is_empty() {
        return None;
    }
    let visible_line = row.saturating_sub(inner.y);
    let line = usize::from(app.details_scroll)
        .saturating_add(usize::from(visible_line))
        .min(document.lines.len().saturating_sub(1));
    let line_width = display_width(&document.lines[line].to_string()).min(usize::from(u16::MAX));
    let column = usize::from(column.saturating_sub(inner.x))
        .min(line_width)
        .min(usize::from(u16::MAX)) as u16;

    Some(DetailsTextPosition { line, column })
}

fn selected_details_text(document: &DetailsDocument, selection: &DetailsTextSelection) -> String {
    if document.lines.is_empty() {
        return String::new();
    }
    let ((start_line, start_col), (end_line, end_col)) = ordered_details_text_range(selection);
    let last_line = end_line.min(document.lines.len().saturating_sub(1));
    if start_line > last_line {
        return String::new();
    }

    let mut lines = Vec::new();
    for line_index in start_line..=last_line {
        if document.copy_skip_lines.contains(&line_index) {
            continue;
        }
        let line = document.lines[line_index].to_string();
        let line_width = display_width(&line);
        let start = if line_index == start_line {
            usize::from(start_col).min(line_width)
        } else {
            0
        };
        let end = if line_index == end_line {
            usize::from(end_col).min(line_width)
        } else {
            line_width
        };
        if let Some(selected) =
            selected_copyable_details_text_line(document, line_index, start, end)
        {
            lines.push(selected);
        }
    }

    lines.join("\n").trim_end_matches('\n').to_string()
}

fn selected_copyable_details_text_line(
    document: &DetailsDocument,
    line_index: usize,
    start: usize,
    end: usize,
) -> Option<String> {
    if start >= end {
        return Some(String::new());
    }

    let text = document.lines[line_index].to_string();
    let mut output = String::new();
    let mut column = 0_usize;
    let mut selected_visible = false;
    let mut selected_copyable = false;
    for ch in text.chars() {
        let width = display_width_char(ch);
        let next_column = column.saturating_add(width);
        if next_column > start && column < end {
            selected_visible = true;
            if !details_copy_excluded(document, line_index, column, next_column) {
                output.push(ch);
                selected_copyable = true;
            }
        }
        column = next_column;
        if column >= end {
            break;
        }
    }

    if selected_visible && !selected_copyable {
        Some(String::new())
    } else {
        Some(output)
    }
}

fn details_copy_excluded(
    document: &DetailsDocument,
    line_index: usize,
    start: usize,
    end: usize,
) -> bool {
    document.copy_exclusions.iter().any(|region| {
        region.line == line_index
            && end > usize::from(region.start)
            && start < usize::from(region.end)
    })
}

fn handle_details_scroll(app: &mut AppState, area: Rect, delta: i16) {
    app.focus = FocusTarget::Details;
    app.search_active = false;
    app.comment_search_active = false;
    app.global_search_active = false;
    app.filter_input_active = false;

    let max_scroll = max_details_scroll(app, area);
    if max_scroll == 0 {
        app.details_scroll = 0;
        app.remember_current_conversation_details_position();
        return;
    }

    if delta < 0 {
        app.details_scroll = app.details_scroll.saturating_sub(delta.unsigned_abs());
    } else {
        app.details_scroll = app.details_scroll.saturating_add(delta as u16);
    }
    app.details_scroll = app.details_scroll.min(max_scroll);
    app.remember_current_conversation_details_position();
}

fn handle_list_scroll(app: &mut AppState, area: Rect, delta: isize) {
    app.focus = FocusTarget::List;
    app.search_active = false;
    app.comment_search_active = false;
    app.global_search_active = false;
    app.filter_input_active = false;
    if app.details_mode == DetailsMode::Diff {
        app.move_diff_file(delta);
    } else {
        app.scroll_list_viewport(area, delta);
    }
}

fn mouse_list_scroll_delta(app: &AppState, direction: isize) -> isize {
    if app.details_mode == DetailsMode::Diff {
        return direction
            .signum()
            .saturating_mul(MOUSE_DIFF_FILE_SCROLL_LINES as isize);
    }

    direction.saturating_mul(MOUSE_LIST_SCROLL_LINES as isize)
}

fn list_page_delta(app: &AppState, area: Option<Rect>, direction: isize) -> isize {
    let rows = area
        .map(|area| {
            let body = body_areas_with_ratio(page_areas(area)[2], app.list_width_percent);
            usize::from(table_visible_rows(body[0]).max(1))
        })
        .unwrap_or(10);
    direction.saturating_mul(rows as isize)
}

fn diff_file_page_delta(app: &AppState, area: Option<Rect>, direction: isize) -> isize {
    let rows = area
        .map(|area| {
            let body = body_areas_with_ratio(page_areas(area)[2], app.list_width_percent);
            usize::from(block_inner(body[0]).height.max(1))
        })
        .unwrap_or(10);
    direction.saturating_mul(rows as isize)
}

fn diff_line_page_delta(app: &AppState, area: Option<Rect>, direction: isize) -> isize {
    let rows = area
        .map(|area| usize::from(block_inner(details_area_for(app, area)).height.max(1)))
        .unwrap_or(10);
    direction.saturating_mul(rows as isize)
}

fn max_details_scroll(app: &AppState, area: Rect) -> u16 {
    let inner = block_inner(area);
    let document = build_details_document(app, inner.width);
    let max = document
        .lines
        .len()
        .saturating_sub(usize::from(inner.height));
    max.min(usize::from(u16::MAX)) as u16
}

fn handle_table_click(
    app: &mut AppState,
    mouse: MouseEvent,
    area: Rect,
    store: Option<&SnapshotStore>,
    tx: Option<&UnboundedSender<AppMsg>>,
) {
    if app.details_mode == DetailsMode::Diff {
        let Some(file_index) = diff_file_row_at(app, area, mouse.row) else {
            return;
        };
        app.select_diff_file(file_index);
        app.focus = FocusTarget::Details;
        return;
    }

    let Some(position) = table_row_at(app, area, mouse.row) else {
        return;
    };

    app.set_selection(position);
    app.focus_details();
    mark_current_notification_read_if_possible(app, store, tx);
}

fn handle_details_hover(app: &mut AppState, mouse: MouseEvent, area: Rect) {
    let inner = block_inner(area);
    if !rect_contains(inner, mouse.column, mouse.row) {
        return;
    }

    let document = build_details_document(app, inner.width);
    let line_index = app.details_scroll as usize + (mouse.row - inner.y) as usize;
    let column = mouse.column - inner.x;
    if document.link_at(line_index, column).is_some() {
        app.status = "link under pointer; click to open".to_string();
    } else if document.action_at(line_index, column).is_some() {
        app.status = "action under pointer; click to run".to_string();
    }
}

fn mark_current_notification_read_if_possible(
    app: &mut AppState,
    store: Option<&SnapshotStore>,
    tx: Option<&UnboundedSender<AppMsg>>,
) {
    if let (Some(store), Some(tx)) = (store, tx) {
        app.mark_current_notification_read(store, tx);
    }
}

fn table_row_at(app: &AppState, area: Rect, row: u16) -> Option<usize> {
    let section = app.current_section()?;
    let filtered_len = app.filtered_indices(section).len();
    if filtered_len == 0 {
        return None;
    }

    let inner = block_inner(area);
    let data_start = inner.y.saturating_add(TABLE_HEADER_HEIGHT);
    if row < data_start {
        return None;
    }

    let visible_rows = table_visible_rows(area);
    if visible_rows == 0 || row >= data_start.saturating_add(visible_rows) {
        return None;
    }

    let offset = app.current_list_scroll_offset(filtered_len, usize::from(visible_rows));
    let position = offset + usize::from(row - data_start);
    (position < filtered_len).then_some(position)
}

fn diff_file_row_at(app: &AppState, area: Rect, row: u16) -> Option<usize> {
    let item = app.current_item()?;
    let diff = match app.diffs.get(&item.id)? {
        DiffState::Loaded(diff) => diff,
        _ => return None,
    };
    let entries = diff_tree_entries(diff);
    if entries.is_empty() {
        return None;
    }

    let inner = block_inner(area);
    if row < inner.y || row >= inner.y.saturating_add(inner.height) {
        return None;
    }

    let selected_file = app.selected_diff_file_index_for(&item.id, diff);
    let selected_row = diff_tree_row_index_for_file(&entries, selected_file).unwrap_or(0);
    let visible_rows = usize::from(inner.height.max(1));
    let offset = table_viewport_offset(selected_row, visible_rows);
    let position = offset + usize::from(row - inner.y);
    entries.get(position).and_then(|entry| entry.file_index)
}

fn table_visible_rows(area: Rect) -> u16 {
    block_inner(area).height.saturating_sub(TABLE_HEADER_HEIGHT)
}

fn table_visible_range(offset: usize, visible_rows: usize, len: usize) -> Option<(usize, usize)> {
    if visible_rows == 0 || len == 0 {
        return None;
    }

    let offset = offset.min(max_table_viewport_offset(len, visible_rows));
    let end = offset.saturating_add(visible_rows).min(len);
    Some((offset + 1, end))
}

fn table_visible_range_label(
    section: &SectionSnapshot,
    unfiltered: bool,
    start: usize,
    end: usize,
    visible_len: usize,
) -> String {
    if unfiltered
        && let (Some(total_count), Some(page_size)) =
            (section.total_count, section_page_size_for_display(section))
    {
        let offset = section.page.saturating_sub(1).saturating_mul(page_size);
        let global_start = offset.saturating_add(start).min(total_count);
        let global_end = offset.saturating_add(end).min(total_count);
        let mut label = format!(" | showing {global_start}-{global_end}/{total_count}");
        if let Some(page_label) = section_page_label(section) {
            label.push_str(&format!(" | page {page_label}"));
        }
        return label;
    }

    let mut label = format!(" | showing {start}-{end}/{visible_len}");
    if let Some(page_label) = section_page_label(section) {
        label.push_str(&format!(" | page {page_label}"));
    }
    label
}

fn table_viewport_offset(selected: usize, visible_rows: usize) -> usize {
    if visible_rows == 0 {
        return 0;
    }
    selected.saturating_sub(visible_rows - 1)
}

fn max_table_viewport_offset(len: usize, visible_rows: usize) -> usize {
    if visible_rows == 0 {
        0
    } else {
        len.saturating_sub(visible_rows)
    }
}

fn view_tab_at(app: &AppState, area: Rect, column: u16, row: u16) -> Option<String> {
    let views = app.view_tabs();
    let labels = views
        .iter()
        .map(|view| view.label.clone())
        .collect::<Vec<_>>();
    tab_index_at(&labels, area, column, row)
        .and_then(|index| views.get(index).map(|view| view.key.clone()))
}

fn section_tab_at(app: &AppState, area: Rect, column: u16, row: u16) -> Option<usize> {
    let labels = app
        .visible_sections()
        .iter()
        .map(|section| section_tab_label(app, section))
        .collect::<Vec<_>>();
    tab_index_at(&labels, area, column, row)
}

fn tab_index_at(labels: &[String], area: Rect, column: u16, row: u16) -> Option<usize> {
    let inner = block_inner(area);
    if !rect_contains(inner, column, row) {
        return None;
    }

    let clicked = column.saturating_sub(inner.x);
    let mut offset = 0_u16;
    for (index, label) in labels.iter().enumerate() {
        let width = display_width(label) as u16;
        let end = offset.saturating_add(width);
        if clicked >= offset && clicked < end {
            return Some(index);
        }
        offset = end.saturating_add(TAB_DIVIDER_WIDTH);
    }

    None
}

fn draw(frame: &mut Frame<'_>, app: &AppState, paths: &Paths) {
    set_active_theme(app.theme_name);
    let area = frame.area();
    frame.buffer_mut().set_style(area, active_theme().base());
    let chunks = page_areas(area);

    draw_view_tabs(frame, app, chunks[0]);
    draw_top_status(frame, app, area);
    draw_section_tabs(frame, app, chunks[1]);

    if app.mouse_capture_enabled {
        let body = body_areas_with_ratio(chunks[2], app.list_width_percent);
        if app.details_mode == DetailsMode::Diff {
            draw_diff_files(frame, app, body[0]);
        } else {
            draw_table(frame, app, body[0]);
        }
        draw_details(frame, app, body[1]);
    } else {
        draw_details(frame, app, chunks[2]);
    }
    draw_footer(frame, app, paths, chunks[3]);

    if let Some(dialog) = app.setup_dialog {
        draw_setup_dialog(frame, dialog, area);
    } else if let Some(dialog) = app.startup_dialog {
        draw_startup_dialog(frame, app, paths, dialog, area);
    } else if let Some(dialog) = &app.message_dialog {
        draw_message_dialog(frame, dialog, area);
    } else if app.help_dialog {
        draw_help_dialog(frame, area, &app.command_palette_key);
    } else if let Some(dialog) = &app.item_edit_dialog {
        draw_item_edit_dialog(frame, dialog, area);
    } else if let Some(dialog) = &app.pr_action_dialog {
        draw_pr_action_dialog(frame, dialog, app.pr_action_running, area);
    } else if let Some(dialog) = &app.label_dialog {
        draw_label_dialog(frame, dialog, app.label_updating, area);
    } else if let Some(dialog) = &app.issue_dialog {
        draw_issue_dialog(frame, dialog, app.issue_creating, area);
    } else if let Some(dialog) = &app.pr_create_dialog {
        draw_pr_create_dialog(frame, dialog, app.pr_creating, area);
    } else if let Some(dialog) = &app.reaction_dialog {
        draw_reaction_dialog(frame, dialog, app.posting_reaction, area);
    } else if let Some(dialog) = &app.review_submit_dialog {
        draw_review_submit_dialog(frame, dialog, area);
    } else if let Some(dialog) = &app.milestone_dialog {
        draw_milestone_dialog(frame, dialog, app.milestone_action_running, area);
    } else if let Some(dialog) = &app.assignee_dialog {
        draw_assignee_dialog(frame, dialog, app.assignee_action_running, area);
    } else if let Some(dialog) = &app.reviewer_dialog {
        draw_reviewer_dialog(frame, dialog, app.reviewer_action_running, area);
    } else if let Some(dialog) = &app.comment_dialog {
        draw_comment_dialog(frame, dialog, area);
    } else if app.global_search_active {
        if let Some(dialog) = &app.global_search_dialog {
            draw_global_search_dialog(frame, dialog, app, area);
        }
    } else if app.global_search_running {
        draw_global_search_loading_dialog(frame, app, area);
    } else if let Some(loading) = &app.section_page_loading {
        draw_section_page_loading_dialog(frame, loading, area);
    }

    if let Some(palette) = &app.command_palette {
        draw_command_palette(frame, app, palette, area, &app.command_palette_key);
    }
    if let Some(switcher) = &app.project_switcher {
        draw_project_switcher(frame, app, switcher, area);
    }
    if let Some(switcher) = &app.top_menu_switcher {
        draw_top_menu_switcher(frame, app, switcher, area);
    }
    if let Some(dialog) = &app.recent_items_dialog {
        draw_recent_items_dialog(frame, app, dialog, area);
    }
    if let Some(dialog) = &app.saved_search_dialog {
        draw_saved_search_dialog(frame, app, dialog, area);
    }
    if let Some(dialog) = &app.save_search_dialog {
        draw_save_search_dialog(frame, dialog, area);
    }
    if let Some(dialog) = &app.project_add_dialog {
        draw_project_add_dialog(frame, dialog, area);
    }
    if let Some(dialog) = &app.project_remove_dialog {
        draw_project_remove_dialog(frame, dialog, area);
    }
    if let Some(dialog) = &app.cache_clear_dialog {
        draw_cache_clear_dialog(frame, dialog, area);
    }
}

fn draw_view_tabs(frame: &mut Frame<'_>, app: &AppState, area: Rect) {
    let views = app.view_tabs();
    let titles = views
        .iter()
        .map(|view| Line::from(view.label.clone()))
        .collect::<Vec<_>>();
    let active = views
        .iter()
        .position(|view| view.key == app.active_view)
        .unwrap_or(0);
    let ghr_focused = app.focus == FocusTarget::Ghr;
    let border_style = if ghr_focused {
        active_theme().focus_border()
    } else {
        active_theme().border()
    };
    let border_type = if ghr_focused {
        BorderType::Thick
    } else {
        BorderType::Plain
    };
    let title = if ghr_focused { "[Focus] ghr" } else { "ghr" };
    let title_style = view_tabs_title_style(app, border_style);

    let tabs = Tabs::new(titles)
        .select(active)
        .block(
            Block::default()
                .borders(Borders::ALL)
                .border_type(border_type)
                .border_style(border_style)
                .style(active_theme().panel())
                .title(Span::styled(title, title_style)),
        )
        .style(active_theme().muted())
        .highlight_style(active_view_tab_style());
    frame.render_widget(tabs, area);
}

fn view_tabs_title_style(app: &AppState, base_style: Style) -> Style {
    if app.focus == FocusTarget::Ghr || app.has_unread_notifications() {
        base_style.add_modifier(Modifier::BOLD)
    } else {
        base_style
    }
}

fn draw_section_tabs(frame: &mut Frame<'_>, app: &AppState, area: Rect) {
    let sections = app.visible_sections();
    if sections.is_empty() {
        frame.render_widget(
            Paragraph::new("No sections configured").block(Block::default().borders(Borders::ALL)),
            area,
        );
        return;
    }

    let titles = sections
        .iter()
        .map(|section| Line::from(section_tab_label(app, section)))
        .collect::<Vec<_>>();
    let sections_focused = app.focus == FocusTarget::Sections;
    let border_style = if sections_focused {
        active_theme().focus_border()
    } else {
        active_theme().border()
    };
    let border_type = if sections_focused {
        BorderType::Thick
    } else {
        BorderType::Plain
    };
    let title = if sections_focused {
        "[Focus] Sections"
    } else {
        "Sections"
    };

    let tabs = Tabs::new(titles)
        .select(app.current_section_position())
        .block(
            Block::default()
                .borders(Borders::ALL)
                .border_type(border_type)
                .border_style(border_style)
                .style(active_theme().panel())
                .title(Span::styled(title, border_style)),
        )
        .style(active_theme().muted())
        .highlight_style(active_section_tab_style());
    frame.render_widget(tabs, area);
}

fn active_view_tab_style() -> Style {
    active_navigation_tab_style()
}

fn active_section_tab_style() -> Style {
    active_navigation_tab_style()
}

fn active_navigation_tab_style() -> Style {
    active_theme().active()
}

fn section_tab_label(app: &AppState, section: &SectionSnapshot) -> String {
    let title = app
        .quick_filter_label_for_section(section)
        .map(|filter| format!("{} [{filter}]", section.title))
        .unwrap_or_else(|| section.title.clone());
    if matches!(section.kind, SectionKind::Notifications) {
        let unread = notification_unread_count_label(app, section);
        if unread == 0 {
            title
        } else {
            format!("{title} ({unread})")
        }
    } else if !app.search_query.is_empty() {
        format!(
            "{} ({}/{})",
            title,
            app.filtered_indices(section).len(),
            section
                .items
                .len()
                .saturating_sub(app.ignored_count_for_section(section))
        )
    } else {
        let count_label = section_count_label(app, section);
        format!("{title} ({count_label})")
    }
}

fn notification_unread_count_label(app: &AppState, section: &SectionSnapshot) -> usize {
    section
        .items
        .iter()
        .filter(|item| !app.ignored_items.contains(&item.id))
        .filter(|item| item.unread.unwrap_or(false))
        .count()
}

fn section_count_label(app: &AppState, section: &SectionSnapshot) -> String {
    let loaded = section
        .items
        .len()
        .saturating_sub(app.ignored_count_for_section(section));
    match section.total_count {
        Some(total) if total > loaded => format!("{loaded}/{total}"),
        Some(total) => total.to_string(),
        None => loaded.to_string(),
    }
}

fn section_page_size(section: &SectionSnapshot, config: &Config) -> usize {
    if section.page_size > 0 {
        return section.page_size.min(100);
    }
    if !section.items.is_empty() {
        return section.items.len().clamp(1, 100);
    }
    match section.kind {
        SectionKind::PullRequests => config.defaults.pr_per_page,
        SectionKind::Issues => config.defaults.issue_per_page,
        SectionKind::Notifications => config.defaults.notification_limit,
    }
    .clamp(1, 100)
}

fn section_page_size_for_display(section: &SectionSnapshot) -> Option<usize> {
    if section.page_size > 0 {
        Some(section.page_size)
    } else if !section.items.is_empty() {
        Some(section.items.len().clamp(1, 100))
    } else {
        None
    }
}

fn section_total_pages(total_count: usize, page_size: usize) -> (usize, bool) {
    let accessible = total_count.clamp(1, SEARCH_RESULT_WINDOW);
    let total_pages = accessible.div_ceil(page_size.max(1)).max(1);
    (total_pages, total_count > SEARCH_RESULT_WINDOW)
}

fn section_page_label(section: &SectionSnapshot) -> Option<String> {
    let total_count = section.total_count?;
    let page_size = section_page_size_for_display(section)?;
    let (total_pages, total_is_capped) = section_total_pages(total_count, page_size);
    Some(section_page_status_label(
        section.page.max(1).min(total_pages),
        total_pages,
        total_is_capped,
    ))
}

fn section_page_status_label(page: usize, total_pages: usize, total_is_capped: bool) -> String {
    if total_is_capped {
        format!("{page}/{total_pages}+")
    } else {
        format!("{page}/{total_pages}")
    }
}

fn draw_table(frame: &mut Frame<'_>, app: &AppState, area: Rect) {
    let Some(section) = app.current_section() else {
        frame.render_widget(
            Paragraph::new("No data").block(Block::default().borders(Borders::ALL)),
            area,
        );
        return;
    };

    let filtered_indices = app.filtered_indices(section);
    let rows = filtered_indices
        .iter()
        .filter_map(|index| section.items.get(*index))
        .map(|item| {
            let row_style = list_item_row_style(app, item);
            Row::new(list_table_cells(section.kind, item)).style(row_style)
        })
        .collect::<Vec<_>>();
    let empty_state = rows
        .is_empty()
        .then(|| list_empty_state_message(app, section, &filtered_indices))
        .flatten();

    let list_focused = app.focus == FocusTarget::List;
    let header_style = if list_focused {
        active_theme().focus_border()
    } else {
        active_theme().subtle().add_modifier(Modifier::BOLD)
    };
    let header = Row::new(list_table_header(section.kind))
        .style(header_style)
        .bottom_margin(1);

    let mut title = if app.search_query.is_empty() {
        section.title.clone()
    } else {
        format!(
            "{} - {} / {} matching '{}'",
            section.title,
            filtered_indices.len(),
            section.items.len(),
            app.search_query
        )
    };
    if let Some(filter) = app.quick_filter_label_for_section(section) {
        title.push_str(&format!(" | filter: {filter}"));
    }
    if let Some(error) = &section.error {
        title.push_str(&format!(" - error: {}", compact_error_label(error)));
    };
    let ignored_count = app.ignored_count_for_section(section);
    if ignored_count > 0 {
        title.push_str(&format!(" | {ignored_count} ignored"));
    }
    let visible_rows = usize::from(table_visible_rows(area));
    let table_offset = app.current_list_scroll_offset(filtered_indices.len(), visible_rows);
    if let Some((start, end)) =
        table_visible_range(table_offset, visible_rows, filtered_indices.len())
    {
        title.push_str(&table_visible_range_label(
            section,
            app.search_query.is_empty() && ignored_count == 0,
            start,
            end,
            filtered_indices.len(),
        ));
    }

    let input_prompt = active_list_input_prompt(app);
    let (border_style, title_style, border_type, highlight_style) = if app.dragging_split {
        (
            active_theme()
                .panel()
                .fg(active_theme().action)
                .add_modifier(Modifier::BOLD),
            active_theme()
                .panel()
                .fg(active_theme().highlight_fg)
                .bg(active_theme().action)
                .add_modifier(Modifier::BOLD),
            BorderType::Thick,
            active_theme()
                .panel()
                .fg(active_theme().highlight_fg)
                .bg(active_theme().action)
                .add_modifier(Modifier::BOLD),
        )
    } else if let Some((_, color)) = &input_prompt {
        (
            active_theme()
                .panel()
                .fg(*color)
                .add_modifier(Modifier::BOLD),
            active_theme()
                .panel()
                .fg(active_theme().highlight_fg)
                .bg(*color)
                .add_modifier(Modifier::BOLD),
            BorderType::Thick,
            active_theme()
                .panel()
                .fg(active_theme().highlight_fg)
                .bg(*color)
                .add_modifier(Modifier::BOLD),
        )
    } else if list_focused {
        (
            active_theme().focus_border(),
            active_theme().active(),
            BorderType::Thick,
            active_theme().active(),
        )
    } else {
        (
            active_theme().border(),
            active_theme().muted(),
            BorderType::Plain,
            active_theme().selected(),
        )
    };
    if let Some((prompt, _)) = input_prompt {
        title = format!("{prompt} | {title}");
    }
    let title = focus_panel_title("List", &title, list_focused);

    let table = Table::new(rows, list_table_constraints(section.kind))
        .header(header)
        .style(active_theme().panel())
        .block(
            Block::default()
                .borders(Borders::ALL)
                .border_type(border_type)
                .border_style(border_style)
                .title(Span::styled(title, title_style)),
        )
        .row_highlight_style(highlight_style)
        .highlight_spacing(HighlightSpacing::Always)
        .highlight_symbol("> ");

    let mut table_state = TableState::default().with_offset(table_offset);
    let selected = app.current_selected_position();
    if !filtered_indices.is_empty()
        && selected >= table_offset
        && selected < table_offset.saturating_add(visible_rows)
    {
        table_state.select(Some(selected));
    }
    frame.render_stateful_widget(table, area, &mut table_state);
    if let Some((message, style)) = empty_state {
        draw_list_empty_state_message(frame, area, &message, style);
    }
}

fn list_table_cells(kind: SectionKind, item: &WorkItem) -> Vec<String> {
    let mut cells = vec![
        item.repo.clone(),
        item.number
            .map(|number| format!("#{number}"))
            .unwrap_or_default(),
        item.title.clone(),
        relative_time(item.updated_at),
    ];
    if !matches!(kind, SectionKind::Notifications) {
        cells.push(item_meta(item));
    }
    cells
}

fn list_table_header(kind: SectionKind) -> Vec<&'static str> {
    if matches!(kind, SectionKind::Notifications) {
        vec!["Repo", "#", "Title", "Updated"]
    } else {
        vec!["Repo", "#", "Title", "Updated", "Meta"]
    }
}

fn list_table_constraints(kind: SectionKind) -> Vec<Constraint> {
    if matches!(kind, SectionKind::Notifications) {
        vec![
            Constraint::Length(20),
            Constraint::Length(8),
            Constraint::Min(20),
            Constraint::Length(8),
        ]
    } else {
        vec![
            Constraint::Length(20),
            Constraint::Length(8),
            Constraint::Min(20),
            Constraint::Length(8),
            Constraint::Length(14),
        ]
    }
}

fn list_item_row_style(app: &AppState, item: &WorkItem) -> Style {
    match item.unread {
        Some(true) => active_theme()
            .panel()
            .fg(active_theme().text)
            .add_modifier(Modifier::BOLD),
        Some(false) => active_theme().subtle(),
        None if app.item_has_unseen_details(item) => {
            active_theme().panel().add_modifier(Modifier::BOLD)
        }
        None => active_theme().panel(),
    }
}

fn draw_list_empty_state_message(frame: &mut Frame<'_>, area: Rect, message: &str, style: Style) {
    let inner = block_inner(area);
    if inner.height <= 2 || inner.width <= 2 {
        return;
    }

    let message_area = Rect::new(
        inner.x.saturating_add(1),
        inner.y.saturating_add(2),
        inner.width.saturating_sub(2),
        1,
    );
    let width = usize::from(message_area.width.max(1));
    frame.render_widget(
        Paragraph::new(Line::from(Span::styled(
            truncate_inline(message, width),
            style,
        ))),
        message_area,
    );
}

fn list_empty_state_message(
    app: &AppState,
    section: &SectionSnapshot,
    filtered_indices: &[usize],
) -> Option<(String, Style)> {
    if !filtered_indices.is_empty() {
        return None;
    }
    if let Some(error) = &section.error {
        return Some((
            format!("Error: {}", compact_error_label(error)),
            active_theme().panel().fg(active_theme().error),
        ));
    }
    if section.items.is_empty() && section.refreshed_at.is_none() {
        if app.refreshing {
            let message = if section_view_key(section).starts_with("repo:") {
                "Git repo is loading ..."
            } else {
                "GitHub data is loading ..."
            };
            return Some((message.to_string(), active_theme().muted()));
        }
        return Some((
            "No cached data yet. Press r to refresh.".to_string(),
            active_theme().subtle(),
        ));
    }
    if section.items.is_empty() {
        return Some(("No items found.".to_string(), active_theme().subtle()));
    }
    if app.ignored_count_for_section(section) == section.items.len() {
        return Some((
            "All loaded items are ignored. Use the command palette to clear ignored items."
                .to_string(),
            active_theme().subtle(),
        ));
    }
    if !app.search_query.is_empty() {
        return Some((
            "No items match the current search.".to_string(),
            active_theme().subtle(),
        ));
    }
    None
}

fn draw_diff_files(frame: &mut Frame<'_>, app: &AppState, area: Rect) {
    let files_focused = app.focus == FocusTarget::List;
    let (border_style, title_style, border_type, highlight_style) = if app.dragging_split {
        (
            active_theme()
                .panel()
                .fg(active_theme().action)
                .add_modifier(Modifier::BOLD),
            active_theme()
                .panel()
                .fg(active_theme().highlight_fg)
                .bg(active_theme().action)
                .add_modifier(Modifier::BOLD),
            BorderType::Thick,
            active_theme()
                .panel()
                .fg(active_theme().highlight_fg)
                .bg(active_theme().action)
                .add_modifier(Modifier::BOLD),
        )
    } else if files_focused {
        (
            active_theme().focus_border(),
            active_theme().active(),
            BorderType::Thick,
            active_theme().active(),
        )
    } else {
        (
            active_theme().border(),
            active_theme().panel().fg(active_theme().success),
            BorderType::Plain,
            active_theme().selected(),
        )
    };

    let title;
    let mut selected_row = None;
    let rows = match app.current_diff() {
        Some(DiffState::Loaded(diff)) => {
            title = format!(
                "Files | {} file(s) | +{} -{}",
                diff.files.len(),
                diff.additions,
                diff.deletions
            );
            let comment_counts = app
                .current_item()
                .and_then(|item| app.loaded_comments_for_item(&item.id))
                .map(|comments| diff_file_comment_counts(diff, comments))
                .unwrap_or_default();
            let entries = diff_tree_entries_with_comment_counts(diff, &comment_counts);
            if let Some(item_id) = app.current_item().map(|item| item.id.as_str()) {
                let selected_file = app.selected_diff_file_index_for(item_id, diff);
                selected_row = diff_tree_row_index_for_file(&entries, selected_file);
            }
            entries
                .into_iter()
                .map(|entry| {
                    let indent = "  ".repeat(entry.depth);
                    let (marker, style) = if entry.file_index.is_some() {
                        (" ", active_theme().panel())
                    } else {
                        ("▾ ", active_theme().panel().fg(active_theme().success))
                    };
                    let label = format!("{indent}{marker}{}", entry.label);
                    Row::new(diff_tree_row_cells(label, entry.stats)).style(style)
                })
                .collect::<Vec<_>>()
        }
        Some(DiffState::Error(error)) => {
            title = "Files | error".to_string();
            vec![
                Row::new(diff_tree_row_cells(compact_error_label(error), None))
                    .style(active_theme().panel().fg(active_theme().error)),
            ]
        }
        Some(DiffState::Loading) | None => {
            title = "Files | loading".to_string();
            vec![
                Row::new(diff_tree_row_cells("loading diff...".to_string(), None))
                    .style(active_theme().muted()),
            ]
        }
    };

    let title = focus_panel_title("List", &title, files_focused);
    let table = Table::new(
        rows,
        [
            Constraint::Min(12),
            Constraint::Length(1),
            Constraint::Length(5),
            Constraint::Length(5),
            Constraint::Length(4),
            Constraint::Length(8),
        ],
    )
    .style(active_theme().panel())
    .block(
        Block::default()
            .borders(Borders::ALL)
            .border_type(border_type)
            .border_style(border_style)
            .title(Span::styled(title, title_style)),
    )
    .row_highlight_style(highlight_style)
    .highlight_symbol("> ");

    let mut table_state = TableState::default();
    table_state.select(selected_row);
    frame.render_stateful_widget(table, area, &mut table_state);
}

fn diff_tree_row_cells(label: String, stats: Option<DiffFileStats>) -> Vec<Cell<'static>> {
    let Some(stats) = stats else {
        return vec![
            Cell::from(label),
            Cell::from(""),
            Cell::from(""),
            Cell::from(""),
            Cell::from(""),
            Cell::from(""),
        ];
    };

    vec![
        Cell::from(label),
        Cell::from(stats.status),
        right_aligned_cell(format!("+{}", stats.additions)),
        right_aligned_cell(format!("-{}", stats.deletions)),
        right_aligned_cell(if stats.comments > 0 {
            format!("{}c", stats.comments)
        } else {
            String::new()
        }),
        Cell::from(""),
    ]
}

fn right_aligned_cell(text: String) -> Cell<'static> {
    Cell::new(Text::from(text).alignment(Alignment::Right))
}

fn active_list_input_prompt(app: &AppState) -> Option<(String, Color)> {
    let theme = active_theme();
    if app.filter_input_active {
        return Some((
            format!(
                "Filter: f{}_  Enter apply  empty/clear resets  Esc cancel",
                app.filter_input_query
            ),
            theme.focus,
        ));
    }

    if app.global_search_active {
        let scope = app
            .global_search_scope
            .clone()
            .or_else(|| app.current_repo_scope())
            .map(|repo| format!(" in {repo}"))
            .unwrap_or_default();
        return Some((
            format!(
                "Repo Search{scope}: dialog open  Enter choose/search  Ctrl+S save  Ctrl+U clear  Esc cancel"
            ),
            theme.action,
        ));
    }

    if app.is_global_search_results_view() {
        return Some((
            format!("Search results: {}  Esc back", app.global_search_query),
            theme.action,
        ));
    }

    if app.search_active {
        return Some((
            format!(
                "Local Search: /{}_  Enter search  Esc clear",
                app.search_query
            ),
            theme.search,
        ));
    }

    None
}

fn active_details_input_prompt(app: &AppState) -> Option<(String, Color)> {
    let theme = active_theme();
    if app.comment_search_active {
        return Some((
            format!(
                "Comment Search: /{}_  Enter keep  Esc clear",
                app.comment_search_query
            ),
            theme.search,
        ));
    }

    let query = app.comment_search_query.trim();
    if app.focus == FocusTarget::Details
        && app.details_mode == DetailsMode::Conversation
        && !query.is_empty()
    {
        return Some((
            format!("Comment Search: /{query}  n/p results  Esc clear"),
            theme.search,
        ));
    }

    None
}

fn draw_details(frame: &mut Frame<'_>, app: &AppState, area: Rect) {
    let text_selection_mode = !app.mouse_capture_enabled;
    let details_focused = app.focus == FocusTarget::Details;
    let details_prompt = active_details_input_prompt(app);
    let raw_title = details_prompt
        .as_ref()
        .map(|(prompt, _)| format!("{} {prompt}", details_title()))
        .unwrap_or_else(|| details_title().to_string());
    let prompt_color = details_prompt.as_ref().map(|(_, color)| *color);
    let title = focus_panel_title("Details", &raw_title, details_focused);
    let (border_style, mut title_style, border_type) = if app.dragging_split {
        (
            active_theme()
                .panel()
                .fg(active_theme().action)
                .add_modifier(Modifier::BOLD),
            active_theme()
                .panel()
                .fg(active_theme().highlight_fg)
                .bg(active_theme().action)
                .add_modifier(Modifier::BOLD),
            BorderType::Thick,
        )
    } else if details_focused {
        (
            active_theme().focus_alt_border(),
            active_theme()
                .panel()
                .fg(active_theme().highlight_fg)
                .bg(active_theme().focus_alt)
                .add_modifier(Modifier::BOLD),
            BorderType::Thick,
        )
    } else {
        (
            active_theme().border(),
            active_theme()
                .panel()
                .fg(active_theme().action)
                .add_modifier(Modifier::BOLD),
            BorderType::Plain,
        )
    };
    if let Some(color) = prompt_color {
        title_style = active_theme()
            .panel()
            .fg(color)
            .add_modifier(Modifier::BOLD);
    }

    let document_width = if text_selection_mode {
        area.width
    } else {
        area.width.saturating_sub(2)
    };
    let mut document = build_details_document(app, document_width);
    apply_details_text_selection(app, &mut document);

    frame.render_widget(Clear, area);
    if text_selection_mode {
        let details = Paragraph::new(Text::from(document.lines))
            .style(active_theme().panel())
            .scroll((app.details_scroll, 0));
        frame.render_widget(details, area);
        return;
    }

    let details = Paragraph::new(Text::from(document.lines))
        .style(active_theme().panel())
        .block(
            Block::default()
                .borders(Borders::ALL)
                .border_type(border_type)
                .border_style(border_style)
                .title(Span::styled(title, title_style)),
        )
        .scroll((app.details_scroll, 0));
    frame.render_widget(details, area);
}

fn apply_details_text_selection(app: &AppState, document: &mut DetailsDocument) {
    let Some(item_id) = app.current_item().map(|item| item.id.as_str()) else {
        return;
    };
    let Some(selection) = app
        .details_text_selection
        .as_ref()
        .filter(|selection| selection.item_id == item_id)
    else {
        return;
    };
    let ((start_line, start_col), (end_line, end_col)) = ordered_details_text_range(selection);
    if start_line == end_line && start_col == end_col {
        return;
    }
    if document.lines.is_empty() {
        return;
    }

    let last_line = end_line.min(document.lines.len().saturating_sub(1));
    for line_index in start_line..=last_line {
        let line_exclusions = document
            .copy_exclusions
            .iter()
            .filter(|region| region.line == line_index)
            .cloned()
            .collect::<Vec<_>>();
        let line = &mut document.lines[line_index];
        let line_width = display_width(&line.to_string());
        let selection_start = if line_index == start_line {
            usize::from(start_col).min(line_width)
        } else {
            0
        };
        let selection_end = if line_index == end_line {
            usize::from(end_col).min(line_width)
        } else {
            line_width
        };
        if selection_start >= selection_end {
            continue;
        }

        let spans = std::mem::take(&mut line.spans);
        line.spans =
            highlight_details_text_spans(spans, selection_start, selection_end, &line_exclusions);
    }
}

fn ordered_details_text_range(selection: &DetailsTextSelection) -> ((usize, u16), (usize, u16)) {
    let start = (selection.start.line, selection.start.column);
    let end = (selection.end.line, selection.end.column);
    if start <= end {
        (start, end)
    } else {
        (end, start)
    }
}

fn highlight_details_text_spans(
    spans: Vec<Span<'static>>,
    selection_start: usize,
    selection_end: usize,
    exclusions: &[CopyExclusionRegion],
) -> Vec<Span<'static>> {
    let mut highlighted = Vec::new();
    let mut column = 0_usize;
    for span in spans {
        let base_style = span.style;
        let selected_style = details_text_selection_style(base_style);
        for ch in span.content.as_ref().chars() {
            let width = display_width_char(ch);
            let next_column = column.saturating_add(width);
            let selected = next_column > selection_start
                && column < selection_end
                && !selection_highlight_excluded(exclusions, column, next_column);
            push_span_text(
                &mut highlighted,
                ch.to_string(),
                if selected { selected_style } else { base_style },
            );
            column = next_column;
        }
    }
    highlighted
}

fn selection_highlight_excluded(
    exclusions: &[CopyExclusionRegion],
    start: usize,
    end: usize,
) -> bool {
    exclusions
        .iter()
        .any(|region| end > usize::from(region.start) && start < usize::from(region.end))
}

fn details_text_selection_style(base: Style) -> Style {
    base.fg(active_theme().highlight_fg)
        .bg(active_theme().highlight_bg)
        .add_modifier(Modifier::BOLD)
}

fn details_title() -> &'static str {
    "Details"
}

fn focus_panel_title(_label: &str, title: &str, focused: bool) -> String {
    if focused {
        format!("[Focus] {title}")
    } else {
        title.to_string()
    }
}

fn pull_request_changes_url(item: &WorkItem) -> String {
    match item.number {
        Some(number) if !item.repo.trim().is_empty() => {
            format!("https://github.com/{}/pull/{number}/changes", item.repo)
        }
        _ => format!("{}/changes", item.url.trim_end_matches('/')),
    }
}

fn pull_request_commits_url(item: &WorkItem) -> String {
    match item.number {
        Some(number) if !item.repo.trim().is_empty() => {
            format!("https://github.com/{}/pull/{number}/commits", item.repo)
        }
        _ => format!("{}/commits", item.url.trim_end_matches('/')),
    }
}

fn parse_reviewer_logins(input: &str) -> Vec<String> {
    let mut seen = HashSet::new();
    let mut reviewers = Vec::new();
    for login in input
        .split(',')
        .map(str::trim)
        .map(|login| login.trim_start_matches('@').trim())
        .filter(|login| !login.is_empty())
    {
        let key = login.to_ascii_lowercase();
        if seen.insert(key) {
            reviewers.push(login.to_string());
        }
    }
    reviewers
}

fn reviewer_input_prefix(input: &str) -> String {
    input
        .rsplit(',')
        .next()
        .unwrap_or_default()
        .trim()
        .trim_start_matches('@')
        .to_ascii_lowercase()
}

fn reviewer_dialog_suggestion_matches(dialog: &ReviewerDialog) -> Vec<String> {
    let prefix = reviewer_input_prefix(&dialog.input);
    dialog
        .suggestions
        .iter()
        .filter(|login| prefix.is_empty() || login.to_ascii_lowercase().starts_with(&prefix))
        .cloned()
        .collect()
}

fn selected_reviewer_suggestion(dialog: &ReviewerDialog) -> Option<String> {
    let matches = reviewer_dialog_suggestion_matches(dialog);
    if matches.is_empty() {
        None
    } else {
        matches
            .get(dialog.selected_suggestion.min(matches.len() - 1))
            .cloned()
    }
}

fn reviewer_dialog_submit_logins(dialog: &ReviewerDialog) -> Vec<String> {
    let mut reviewers = parse_reviewer_logins(&dialog.input);
    if !reviewers.is_empty()
        && !reviewer_input_prefix(&dialog.input).is_empty()
        && let Some(selected) = selected_reviewer_suggestion(dialog)
        && let Some(last) = reviewers.last_mut()
    {
        *last = selected;
    }
    dedupe_reviewer_logins(reviewers)
}

fn dedupe_reviewer_logins(logins: Vec<String>) -> Vec<String> {
    let mut seen = HashSet::new();
    let mut deduped = Vec::new();
    for login in logins {
        let key = login.to_ascii_lowercase();
        if seen.insert(key) {
            deduped.push(login);
        }
    }
    deduped
}

fn same_view_key(left: &str, right: &str) -> bool {
    left == right
        || (left.starts_with("repo:")
            && right.starts_with("repo:")
            && left.eq_ignore_ascii_case(right))
}

fn view_supports_snapshot(view: &str) -> bool {
    view.starts_with("repo:")
}

fn section_repo_scope(section: &SectionSnapshot) -> Option<String> {
    section
        .filters
        .split_whitespace()
        .find_map(repo_token_value)
}

fn created_issue_matches_section(
    section: &SectionSnapshot,
    item: &WorkItem,
    active_view: &str,
) -> bool {
    if section.kind != SectionKind::Issues {
        return false;
    }

    match section_repo_scope(section) {
        Some(repo) => repo == item.repo,
        None => same_view_key(&section_view_key(section), active_view),
    }
}

fn created_pull_request_matches_section(
    section: &SectionSnapshot,
    item: &WorkItem,
    active_view: &str,
) -> bool {
    if section.kind != SectionKind::PullRequests {
        return false;
    }

    match section_repo_scope(section) {
        Some(repo) => repo.eq_ignore_ascii_case(&item.repo),
        None => same_view_key(&section_view_key(section), active_view),
    }
}

fn repo_token_value(token: &str) -> Option<String> {
    token
        .strip_prefix("repo:")
        .filter(|repo| !repo.trim().is_empty())
        .map(str::to_string)
}

fn draw_footer(frame: &mut Frame<'_>, app: &AppState, paths: &Paths, area: Rect) {
    let footer = Paragraph::new(footer_line_for_width(app, paths, usize::from(area.width)))
        .style(active_theme().muted());
    frame.render_widget(footer, area);
}

fn draw_top_status(frame: &mut Frame<'_>, app: &AppState, area: Rect) {
    let Some(status_area) = top_status_area(area) else {
        return;
    };
    let line = top_status_line(app, usize::from(status_area.width));
    frame.render_widget(Clear, status_area);
    frame.render_widget(
        Paragraph::new(line)
            .style(active_theme().panel())
            .alignment(Alignment::Right),
        status_area,
    );
}

fn top_status_area(area: Rect) -> Option<Rect> {
    let max_width = area.width.saturating_sub(4).min(46);
    if max_width < 12 || area.height == 0 {
        return None;
    }

    Some(Rect::new(
        area.x + area.width.saturating_sub(max_width).saturating_sub(1),
        area.y,
        max_width,
        1,
    ))
}

fn top_status_line(app: &AppState, width: usize) -> Line<'static> {
    let value_width = width.saturating_sub(display_width("status: "));
    let value = truncate_inline(&footer_status(app), value_width);
    let mut spans = Vec::new();
    push_status_spans(&mut spans, value);
    Line::from(fit_footer_spans_to_width(spans, width))
}

#[cfg(test)]
fn footer_line(app: &AppState, paths: &Paths) -> Line<'static> {
    footer_line_for_width(app, paths, usize::MAX)
}

fn footer_line_for_width(app: &AppState, _paths: &Paths, width: usize) -> Line<'static> {
    Line::from(fit_footer_groups(footer_groups(app), width))
}

fn footer_groups(app: &AppState) -> Vec<Vec<Span<'static>>> {
    let search = if app.comment_search_active {
        Some(format!("comment-search: /{}_", app.comment_search_query))
    } else if app.focus == FocusTarget::Details
        && app.details_mode == DetailsMode::Conversation
        && !app.comment_search_query.is_empty()
    {
        Some(format!("comment-search: /{}", app.comment_search_query))
    } else if app.global_search_active {
        Some(
            app.global_search_dialog
                .as_ref()
                .map(|dialog| format!("repo-search: {}", dialog.field.label()))
                .unwrap_or_else(|| "repo-search".to_string()),
        )
    } else if app.global_search_running {
        Some("repo search running".to_string())
    } else if app.filter_input_active {
        Some(format!("filter: f{}_", app.filter_input_query))
    } else if app.search_active {
        Some(format!("local-search: /{}_", app.search_query))
    } else if app.search_query.is_empty() {
        None
    } else {
        Some(format!("local-search: /{}", app.search_query))
    };
    let active_filter = app.current_filter_label();
    let (mouse, text_selection_state) = footer_mouse_shortcut(app);

    let mut groups = Vec::new();

    groups.push(footer_focus_primary_shortcuts(app));

    if let Some(search) = search {
        let mut spans = Vec::new();
        push_footer_state(&mut spans, "search", search, Color::Yellow);
        groups.push(spans);
    }
    if let Some(active_filter) = active_filter {
        let mut spans = Vec::new();
        push_footer_state(&mut spans, "filter", active_filter, Color::LightCyan);
        groups.push(spans);
    }
    if let Some(text_selection_state) = text_selection_state {
        let mut spans = Vec::new();
        push_footer_state(&mut spans, "mode", text_selection_state, Color::LightBlue);
        groups.push(spans);
    }

    groups.push(footer_global_primary_shortcuts(app));
    if let Some(mouse) = mouse {
        let mut spans = Vec::new();
        push_footer_pair(&mut spans, "m", mouse, Color::LightBlue);
        groups.push(spans);
    }

    groups
        .into_iter()
        .filter(|group| !group.is_empty())
        .collect()
}

fn footer_status(app: &AppState) -> String {
    if let Some(loading) = &app.section_page_loading {
        section_page_loading_status(loading)
    } else if app.refreshing {
        "refreshing".to_string()
    } else {
        app.status.clone()
    }
}

fn footer_mouse_shortcut(app: &AppState) -> (Option<&'static str>, Option<&'static str>) {
    if !app.mouse_capture_enabled {
        return (Some("restore mouse"), Some("text-select: drag copy"));
    }
    if app.details_mode == DetailsMode::Diff {
        return (None, None);
    }
    (Some("text-select"), None)
}

fn footer_has_selected_comment(app: &AppState) -> bool {
    app.details_mode == DetailsMode::Conversation
        && app
            .current_selected_comment()
            .is_some_and(|comment| !comment.kind.is_activity())
}

fn footer_selected_comment_is_editable(app: &AppState) -> bool {
    app.details_mode == DetailsMode::Conversation
        && app
            .current_selected_comment()
            .is_some_and(|comment| comment.is_mine && comment.id.is_some())
}

fn footer_focus_primary_shortcuts(app: &AppState) -> Vec<Span<'static>> {
    let mut spans = Vec::new();
    if let Some(dialog) = &app.pr_action_dialog {
        push_footer_pair(&mut spans, "y/enter", "run", Color::Yellow);
        push_footer_pair(&mut spans, "esc", "cancel", Color::Cyan);
        if dialog.action == PrAction::Merge {
            push_footer_pair(&mut spans, "m/s/r", "method", Color::LightMagenta);
        }
        return spans;
    }

    match app.focus {
        FocusTarget::Ghr => {
            push_footer_pair(&mut spans, "tab/h/l", "switch", Color::Cyan);
            push_footer_pair(&mut spans, "j/n/enter", "Sections", Color::Cyan);
            push_footer_pair(&mut spans, "esc", "List", Color::Cyan);
        }
        FocusTarget::Sections => {
            push_footer_pair(&mut spans, "tab/h/l", "switch", Color::Cyan);
            push_footer_pair(&mut spans, "k/p", "ghr", Color::Cyan);
            push_footer_pair(&mut spans, "j/n/enter", "List", Color::Cyan);
            push_footer_pair(&mut spans, "esc", "List", Color::Cyan);
        }
        FocusTarget::List => {
            if app.details_mode == DetailsMode::Diff {
                push_footer_pair(&mut spans, "j/k", "file", Color::Cyan);
                push_footer_pair(&mut spans, "tab", "diff", Color::Cyan);
                push_footer_pair(&mut spans, "enter", "diff", Color::Cyan);
                push_footer_pair(&mut spans, "esc", "back", Color::Cyan);
                push_footer_pair(&mut spans, "[ ]", "file", Color::Cyan);
                push_footer_pair(&mut spans, "i", "comments", Color::Yellow);
                push_footer_pair(&mut spans, "c", "inline", Color::LightBlue);
                push_footer_pair(&mut spans, "a", "comment", Color::LightBlue);
            } else {
                push_footer_pair(&mut spans, "j/k/n/p", "move", Color::Cyan);
                push_footer_pair(&mut spans, "[ ]", "page", Color::Cyan);
                push_footer_pair(&mut spans, "tab", "Details", Color::Cyan);
                push_footer_pair(&mut spans, "enter", "Details", Color::Cyan);
                push_footer_pair(&mut spans, "/", "search", Color::Yellow);
                if app.is_global_search_results_view() {
                    push_footer_pair(&mut spans, "esc", "back", Color::Cyan);
                }
                push_footer_pair(&mut spans, "v", "diff", Color::LightMagenta);
                push_footer_pair(&mut spans, "i", "ignore", Color::LightRed);
                push_footer_pair(&mut spans, "a", "comment", Color::LightBlue);
            }
        }
        FocusTarget::Details => {
            if app.details_mode == DetailsMode::Diff {
                push_footer_pair(&mut spans, "j/k", "line", Color::Cyan);
                push_footer_pair(&mut spans, "tab", "files", Color::Cyan);
                push_footer_pair(&mut spans, "n/p", "comment", Color::LightBlue);
                push_footer_pair(&mut spans, "h/l", "page", Color::Cyan);
                push_footer_pair(&mut spans, "i", "comments", Color::Yellow);
                push_footer_pair(&mut spans, "c", "inline", Color::LightBlue);
                push_footer_pair(&mut spans, "a", "comment", Color::LightBlue);
            } else {
                push_footer_pair(&mut spans, "j/k", "scroll", Color::Cyan);
                push_footer_pair(&mut spans, "tab", "List", Color::Cyan);
                push_footer_pair(&mut spans, "v", "diff", Color::LightMagenta);
                push_footer_pair(&mut spans, "/", "search", Color::Yellow);
                push_footer_pair(&mut spans, "c/a", "comment", Color::LightBlue);
                if footer_has_selected_comment(app) {
                    push_footer_pair(&mut spans, "n/p", "comment", Color::LightBlue);
                    push_footer_pair(&mut spans, "enter", "expand", Color::Yellow);
                }
                if footer_has_selected_comment(app) {
                    push_footer_pair(&mut spans, "R", "reply", Color::LightBlue);
                }
                if footer_selected_comment_is_editable(app) {
                    push_footer_pair(&mut spans, "e", "edit", Color::LightBlue);
                }
            }
            let esc_action = if app.details_mode == DetailsMode::Diff {
                "back"
            } else {
                "List"
            };
            push_footer_pair(&mut spans, "esc", esc_action, Color::Cyan);
        }
    }
    spans
}

fn footer_global_primary_shortcuts(app: &AppState) -> Vec<Span<'static>> {
    let mut spans = Vec::new();
    push_footer_pair(&mut spans, "?", "help", Color::Yellow);
    push_footer_pair(
        &mut spans,
        app.command_palette_key.clone(),
        "cmd",
        Color::Yellow,
    );
    push_footer_pair(&mut spans, "f", "filter", Color::LightCyan);
    push_footer_pair(&mut spans, "r", "refresh", Color::Yellow);
    let q_action = if app.details_mode == DetailsMode::Diff {
        "back"
    } else {
        "quit"
    };
    push_footer_pair(&mut spans, "q", q_action, Color::Yellow);
    push_footer_pair(&mut spans, "o", "open", Color::Yellow);
    spans
}

fn fit_footer_groups(groups: Vec<Vec<Span<'static>>>, width: usize) -> Vec<Span<'static>> {
    if width == usize::MAX {
        let mut spans = Vec::new();
        for group in groups {
            push_footer_group(&mut spans, group);
        }
        return spans;
    }

    let mut spans = Vec::new();
    let mut omitted = false;
    for group in groups {
        if group.is_empty() {
            continue;
        }

        let separator_width = if spans.is_empty() {
            0
        } else {
            display_width(" | ")
        };
        let group_width = footer_spans_width(&group);
        let next_width = footer_spans_width(&spans)
            .saturating_add(separator_width)
            .saturating_add(group_width);
        if next_width <= width {
            push_footer_group(&mut spans, group);
        } else if spans.is_empty() {
            spans.extend(fit_footer_spans_to_width(group, width));
            omitted = true;
        } else {
            omitted = true;
        }
    }

    if omitted {
        append_footer_more_marker(&mut spans, width);
    }
    spans
}

fn push_footer_group(spans: &mut Vec<Span<'static>>, group: Vec<Span<'static>>) {
    if group.is_empty() {
        return;
    }
    if !spans.is_empty() {
        push_footer_separator(spans);
    }
    spans.extend(group);
}

fn append_footer_more_marker(spans: &mut Vec<Span<'static>>, width: usize) {
    let marker = vec![
        Span::styled("...", active_theme().subtle()),
        Span::raw(" "),
        Span::styled(
            "?",
            active_theme()
                .panel()
                .fg(active_theme().warning)
                .add_modifier(Modifier::BOLD),
        ),
        Span::raw(" "),
        Span::styled("help", active_theme().muted()),
    ];
    let separator_width = if spans.is_empty() {
        0
    } else {
        display_width(" | ")
    };
    let next_width = footer_spans_width(spans)
        .saturating_add(separator_width)
        .saturating_add(footer_spans_width(&marker));
    if next_width <= width {
        push_footer_group(spans, marker);
    }
}

fn fit_footer_spans_to_width(spans: Vec<Span<'static>>, width: usize) -> Vec<Span<'static>> {
    let mut fitted = Vec::new();
    let mut used = 0_usize;
    for span in spans {
        let content = span.content.as_ref();
        let span_width = display_width(content);
        if used.saturating_add(span_width) <= width {
            used = used.saturating_add(span_width);
            fitted.push(span);
            continue;
        }

        let remaining = width.saturating_sub(used);
        if remaining > 0 {
            fitted.push(Span::styled(
                truncate_inline(content, remaining),
                span.style,
            ));
        }
        break;
    }
    fitted
}

fn footer_spans_width(spans: &[Span<'static>]) -> usize {
    spans
        .iter()
        .map(|span| display_width(span.content.as_ref()))
        .sum()
}

fn push_footer_separator(spans: &mut Vec<Span<'static>>) {
    spans.push(Span::styled(" | ", active_theme().subtle()));
}

fn push_status_spans(spans: &mut Vec<Span<'static>>, value: impl Into<String>) {
    if !spans.is_empty() && !footer_ends_with_separator(spans) {
        spans.push(Span::raw("  "));
    }
    spans.push(Span::styled(
        "status:",
        active_theme()
            .panel()
            .fg(active_theme().focus)
            .add_modifier(Modifier::BOLD),
    ));
    spans.push(Span::raw(" "));
    spans.push(Span::styled(
        value.into(),
        active_theme().panel().fg(themed_status_value_color()),
    ));
}

fn push_footer_pair(
    spans: &mut Vec<Span<'static>>,
    key: impl Into<String>,
    label: impl Into<String>,
    key_color: Color,
) {
    let key_color = themed_hint_color(key_color);
    if !spans.is_empty() && !footer_ends_with_separator(spans) {
        spans.push(Span::raw("  "));
    }
    spans.push(Span::styled(
        key.into(),
        active_theme()
            .panel()
            .fg(key_color)
            .add_modifier(Modifier::BOLD),
    ));
    spans.push(Span::raw(" "));
    spans.push(Span::styled(label.into(), active_theme().muted()));
}

fn push_footer_state(
    spans: &mut Vec<Span<'static>>,
    key: &'static str,
    value: impl Into<String>,
    value_color: Color,
) {
    let value_color = themed_hint_color(value_color);
    if !spans.is_empty() && !footer_ends_with_separator(spans) {
        spans.push(Span::raw("  "));
    }
    spans.push(Span::styled(
        key,
        active_theme()
            .panel()
            .fg(active_theme().subtle)
            .add_modifier(Modifier::BOLD),
    ));
    spans.push(Span::raw(" "));
    spans.push(Span::styled(
        value.into(),
        active_theme().panel().fg(value_color),
    ));
}

fn themed_hint_color(color: Color) -> Color {
    let theme = active_theme();
    match color {
        Color::Cyan | Color::LightCyan => theme.focus,
        Color::LightBlue => theme.link,
        Color::LightMagenta => theme.action,
        Color::Yellow | Color::LightYellow => theme.warning,
        Color::LightRed | Color::Red => theme.error,
        Color::Green | Color::LightGreen => theme.success,
        _ => color,
    }
}

fn themed_fg_style(color: Color) -> Style {
    active_theme().panel().fg(themed_hint_color(color))
}

fn themed_bold_style(color: Color) -> Style {
    themed_fg_style(color).add_modifier(Modifier::BOLD)
}

fn themed_status_value_color() -> Color {
    if active_theme().background == Color::Reset {
        Color::Green
    } else {
        active_theme().success
    }
}

fn footer_ends_with_separator(spans: &[Span<'static>]) -> bool {
    spans
        .last()
        .map(|span| span.content.as_ref() == " | ")
        .unwrap_or(false)
}

fn item_supports_metadata_edit(item: &WorkItem) -> bool {
    matches!(item.kind, ItemKind::Issue | ItemKind::PullRequest) && item.number.is_some()
}

fn modal_surface_style() -> Style {
    active_theme().panel()
}

fn modal_text_style() -> Style {
    active_theme().panel()
}

fn modal_footer_style() -> Style {
    active_theme()
        .panel()
        .fg(active_theme().warning)
        .add_modifier(Modifier::BOLD)
}

fn modal_footer_line(text: impl Into<String>) -> Line<'static> {
    Line::from(Span::styled(text.into(), modal_footer_style()))
}

fn draw_modal_footer(frame: &mut Frame<'_>, area: Rect, dialog_area: Rect, footer: Line<'static>) {
    let Some(footer_area) = modal_footer_area(area, dialog_area) else {
        return;
    };
    let paragraph = Paragraph::new(footer)
        .alignment(Alignment::Center)
        .style(modal_text_style());
    frame.render_widget(Clear, footer_area);
    frame.render_widget(paragraph, footer_area);
}

fn modal_footer_area(area: Rect, dialog_area: Rect) -> Option<Rect> {
    if dialog_area.width == 0 || dialog_area.height == 0 {
        return None;
    }
    let y = dialog_area.y.saturating_add(dialog_area.height);
    (y < area.y.saturating_add(area.height)).then_some(Rect::new(
        dialog_area.x,
        y,
        dialog_area.width,
        1,
    ))
}

fn draw_startup_dialog(
    frame: &mut Frame<'_>,
    app: &AppState,
    paths: &Paths,
    dialog: StartupDialog,
    area: Rect,
) {
    let elapsed_secs = app.last_refresh_request.elapsed().as_secs();
    let (title, lines, show_ok) = startup_dialog_content(dialog, app, paths, elapsed_secs);
    let dialog_area = startup_dialog_area(dialog, area);
    let accent = match dialog {
        StartupDialog::Initializing => Color::Cyan,
        StartupDialog::Ready => Color::LightGreen,
    };
    let accent = themed_hint_color(accent);
    let block = Block::default()
        .borders(Borders::ALL)
        .border_style(active_theme().panel().fg(accent))
        .style(modal_surface_style())
        .title(Span::styled(
            title,
            active_theme()
                .panel()
                .fg(accent)
                .add_modifier(Modifier::BOLD),
        ));
    let paragraph = Paragraph::new(Text::from(lines))
        .block(block)
        .style(modal_text_style())
        .wrap(Wrap { trim: false });

    frame.render_widget(Clear, dialog_area);
    frame.render_widget(paragraph, dialog_area);

    if show_ok {
        let ok = Paragraph::new("[ OK ]").alignment(Alignment::Center).style(
            active_theme()
                .panel()
                .fg(active_theme().highlight_fg)
                .bg(active_theme().success)
                .add_modifier(Modifier::BOLD),
        );
        frame.render_widget(ok, startup_dialog_ok_area(dialog_area));
    }
}

fn startup_dialog_area(dialog: StartupDialog, area: Rect) -> Rect {
    let height = match dialog {
        StartupDialog::Initializing => 11,
        StartupDialog::Ready => 13,
    };
    centered_rect(72, height, area)
}

fn startup_dialog_ok_area(dialog_area: Rect) -> Rect {
    let width = 8.min(dialog_area.width.saturating_sub(4)).max(1);
    let x = dialog_area.x + dialog_area.width.saturating_sub(width) / 2;
    let y = dialog_area.y + dialog_area.height.saturating_sub(2);
    Rect::new(x, y, width, 1)
}

fn startup_dialog_content(
    dialog: StartupDialog,
    app: &AppState,
    paths: &Paths,
    elapsed_secs: u64,
) -> (&'static str, Vec<Line<'static>>, bool) {
    match dialog {
        StartupDialog::Initializing => (
            "Initializing",
            vec![
                Line::from("ghr is preparing your GitHub workspace for the first time."),
                Line::from(""),
                startup_loading_line(elapsed_secs),
                startup_progress_line(elapsed_secs),
                Line::from(""),
                key_value_line("config.toml", paths.config_path.display().to_string()),
                key_value_line("database", paths.db_path.display().to_string()),
                Line::from(""),
                Line::from("Loading cache and refreshing remote data. Please wait ..."),
            ],
            false,
        ),
        StartupDialog::Ready => (
            "Ready",
            vec![
                Line::from("ghr is ready."),
                Line::from(""),
                key_value_line("loaded", startup_loaded_summary(app)),
                key_value_line("config.toml", paths.config_path.display().to_string()),
                Line::from(""),
                Line::from(vec![
                    Span::raw("Press "),
                    Span::styled("?", themed_bold_style(Color::Yellow)),
                    Span::raw(" anytime for the shortcut reference."),
                ]),
                Line::from("Click OK or press Enter/Esc to close this dialog."),
            ],
            true,
        ),
    }
}

fn startup_loading_line(elapsed_secs: u64) -> Line<'static> {
    let dots = match elapsed_secs % 4 {
        0 => "",
        1 => ".",
        2 => "..",
        _ => "...",
    };
    Line::from(vec![
        Span::styled(format!("Loading{dots:<3}"), themed_bold_style(Color::Cyan)),
        Span::styled(
            format!("  {elapsed_secs}s"),
            themed_fg_style(Color::DarkGray),
        ),
    ])
}

fn startup_progress_line(elapsed_secs: u64) -> Line<'static> {
    const WIDTH: usize = 28;
    const FILL: usize = 9;

    let span = WIDTH.saturating_sub(FILL).max(1);
    let offset = (elapsed_secs as usize) % (span + 1);
    let mut bar = String::with_capacity(WIDTH + 2);
    bar.push('[');
    for index in 0..WIDTH {
        if index >= offset && index < offset + FILL {
            bar.push('=');
        } else {
            bar.push(' ');
        }
    }
    bar.push(']');

    Line::from(vec![
        Span::raw("  "),
        Span::styled(bar, themed_fg_style(Color::Cyan)),
    ])
}

fn startup_loaded_summary(app: &AppState) -> String {
    let section_count = app.sections.len();
    let item_count = app
        .sections
        .iter()
        .map(|section| section.items.len())
        .sum::<usize>();
    let error_count = app
        .sections
        .iter()
        .filter(|section| section.error.is_some())
        .count();
    let mut summary = format!("{item_count} item(s) across {section_count} section(s)");
    if error_count > 0 {
        summary.push_str(&format!("; {error_count} refresh error(s)"));
    }
    summary
}

