    fn show_info_dialog(&mut self, config: &Config, paths: &Paths) {
        let body = runtime_info_body(self, config, paths);
        self.message_dialog = Some(info_message_dialog("Info", body));
        self.status = "info".to_string();
        debug!("info dialog opened");
    }

    fn dismiss_command_palette(&mut self) {
        self.command_palette = None;
        self.status = "command palette dismissed".to_string();
    }

    fn handle_command_palette_key(
        &mut self,
        key: KeyEvent,
        config: &mut Config,
        paths: &Paths,
        store: &SnapshotStore,
        tx: &UnboundedSender<AppMsg>,
        area: Option<Rect>,
    ) -> bool {
        match key.code {
            KeyCode::Esc => {
                self.dismiss_command_palette();
                false
            }
            KeyCode::Enter => self.submit_command_palette_selection(config, paths, store, tx, area),
            KeyCode::Down | KeyCode::Tab => {
                self.move_command_palette_selection(1);
                false
            }
            KeyCode::Up | KeyCode::BackTab => {
                self.move_command_palette_selection(-1);
                false
            }
            KeyCode::PageDown => {
                self.move_command_palette_selection(8);
                false
            }
            KeyCode::PageUp => {
                self.move_command_palette_selection(-8);
                false
            }
            KeyCode::Backspace => {
                if let Some(palette) = &mut self.command_palette {
                    palette.query.pop();
                    palette.selected = 0;
                }
                false
            }
            KeyCode::Char(value)
                if !key.modifiers.contains(KeyModifiers::CONTROL)
                    && !key.modifiers.contains(KeyModifiers::ALT) =>
            {
                if let Some(palette) = &mut self.command_palette {
                    palette.query.push(value);
                    palette.selected = 0;
                }
                false
            }
            _ => false,
        }
    }

    fn move_command_palette_selection(&mut self, delta: isize) {
        let Some(query) = self
            .command_palette
            .as_ref()
            .map(|palette| palette.query.clone())
        else {
            return;
        };
        let commands = command_palette_commands(&self.command_palette_key);
        let len = self.command_palette_match_indices(&commands, &query).len();
        if let Some(palette) = &mut self.command_palette {
            palette.selected = move_wrapping(palette.selected, len, delta);
        }
    }

    fn submit_command_palette_selection(
        &mut self,
        config: &mut Config,
        paths: &Paths,
        store: &SnapshotStore,
        tx: &UnboundedSender<AppMsg>,
        area: Option<Rect>,
    ) -> bool {
        let Some(command) = self.selected_command_palette_command() else {
            self.status = "no matching command".to_string();
            return false;
        };

        self.remember_command_palette_selection(&command, Utc::now());
        self.command_palette = None;
        match command.action {
            PaletteAction::Key(key) => {
                handle_key_in_area_mut(self, key, config, paths, store, tx, area)
            }
            PaletteAction::Quit => true,
            PaletteAction::ShowInfo => {
                self.show_info_dialog(config, paths);
                false
            }
            PaletteAction::ShowHelp => {
                self.show_help_dialog();
                false
            }
            PaletteAction::ShowCommandPalette => {
                self.show_command_palette();
                false
            }
            PaletteAction::Refresh => {
                trigger_refresh(self, config, store, tx);
                false
            }
            PaletteAction::RecentItems => {
                self.show_recent_items_dialog();
                false
            }
            PaletteAction::ToggleTheme => {
                self.toggle_theme(config, paths);
                false
            }
            PaletteAction::TopMenuSwitch => {
                self.show_top_menu_switcher();
                false
            }
            PaletteAction::SearchCurrentRepo => {
                self.start_global_search_input_with_store(Some(store), Some(tx));
                false
            }
            PaletteAction::SavedSearchFilter => {
                self.show_saved_search_dialog(config);
                false
            }
            PaletteAction::SwitchProject => {
                self.show_project_switcher();
                false
            }
            PaletteAction::ProjectAdd => {
                self.show_project_add_dialog();
                false
            }
            PaletteAction::ProjectRemove => {
                self.show_project_remove_dialog(config);
                false
            }
            PaletteAction::CopyGithubLink => {
                self.copy_github_link();
                false
            }
            PaletteAction::CopyContent => {
                self.copy_content();
                false
            }
            PaletteAction::ToggleMouseCapture => {
                self.toggle_mouse_capture();
                false
            }
            PaletteAction::OpenSelected => {
                self.open_selected();
                false
            }
            PaletteAction::ShowDiff => {
                self.show_diff();
                false
            }
            PaletteAction::ClearIgnoredItems => {
                self.clear_ignored_items();
                false
            }
            PaletteAction::ClearCache => {
                self.show_cache_clear_dialog();
                false
            }
            PaletteAction::InboxMarkDone => {
                self.mark_current_notification_done(store, tx);
                false
            }
            PaletteAction::InboxMarkAllRead => {
                self.mark_all_inbox_read(store, tx);
                false
            }
            PaletteAction::InboxThreadAction(action) => {
                self.start_inbox_thread_action(action, tx);
                false
            }
        }
    }

    fn selected_command_palette_command(&self) -> Option<PaletteCommand> {
        let palette = self.command_palette.as_ref()?;
        let commands = command_palette_commands(&self.command_palette_key);
        let matches = self.command_palette_match_indices(&commands, &palette.query);
        let selected = palette.selected.min(matches.len().saturating_sub(1));
        matches
            .get(selected)
            .and_then(|index| commands.get(*index))
            .cloned()
    }

    fn command_palette_match_indices(
        &self,
        commands: &[PaletteCommand],
        query: &str,
    ) -> Vec<usize> {
        let mut matches = command_palette_filtered_indices(commands, query);
        matches.sort_by(|left, right| {
            let left_selected_at = self.command_palette_selected_at(&commands[*left]);
            let right_selected_at = self.command_palette_selected_at(&commands[*right]);
            match (left_selected_at, right_selected_at) {
                (Some(left_selected_at), Some(right_selected_at)) => right_selected_at
                    .cmp(&left_selected_at)
                    .then_with(|| left.cmp(right)),
                (Some(_), None) => std::cmp::Ordering::Less,
                (None, Some(_)) => std::cmp::Ordering::Greater,
                (None, None) => left.cmp(right),
            }
        });
        matches
    }

    fn command_palette_selected_at(&self, command: &PaletteCommand) -> Option<DateTime<Utc>> {
        let id = command_palette_command_id(command);
        self.recent_commands
            .iter()
            .find(|item| item.id == id)
            .map(|item| item.selected_at)
    }

    fn remember_command_palette_selection(
        &mut self,
        command: &PaletteCommand,
        selected_at: DateTime<Utc>,
    ) {
        let id = command_palette_command_id(command);
        self.recent_commands.retain(|item| item.id != id);
        self.recent_commands.push(RecentCommand { id, selected_at });
        self.recent_commands
            .sort_by_key(|item| std::cmp::Reverse(item.selected_at));
        self.recent_commands.truncate(MAX_RECENT_COMMANDS);
    }

    fn show_top_menu_switcher(&mut self) {
        let candidates = self.top_menu_switcher_candidates();
        if candidates.is_empty() {
            self.top_menu_switcher = None;
            self.status = "no top menu items".to_string();
            return;
        }

        let selected = candidates
            .iter()
            .position(|candidate| candidate.key == self.active_view)
            .unwrap_or(0);
        self.finish_details_visit(Instant::now());
        self.command_palette = None;
        self.project_switcher = None;
        self.recent_items_dialog = None;
        self.project_add_dialog = None;
        self.project_remove_dialog = None;
        self.cache_clear_dialog = None;
        self.top_menu_switcher = Some(TopMenuSwitcher {
            query: String::new(),
            selected,
        });
        self.status = "top menu switch".to_string();
    }

    fn dismiss_top_menu_switcher(&mut self) {
        self.top_menu_switcher = None;
        self.status = "top menu switch cancelled".to_string();
    }

    fn handle_top_menu_switcher_key(&mut self, key: KeyEvent) {
        match key.code {
            KeyCode::Esc => self.dismiss_top_menu_switcher(),
            KeyCode::Enter => self.submit_top_menu_switcher_selection(),
            KeyCode::Down | KeyCode::Tab => self.move_top_menu_switcher_selection(1),
            KeyCode::Up | KeyCode::BackTab => self.move_top_menu_switcher_selection(-1),
            KeyCode::PageDown => self.move_top_menu_switcher_selection(8),
            KeyCode::PageUp => self.move_top_menu_switcher_selection(-8),
            KeyCode::Backspace => {
                if let Some(switcher) = &mut self.top_menu_switcher {
                    switcher.query.pop();
                    switcher.selected = 0;
                }
            }
            KeyCode::Char(value)
                if !key.modifiers.contains(KeyModifiers::CONTROL)
                    && !key.modifiers.contains(KeyModifiers::ALT) =>
            {
                if let Some(switcher) = &mut self.top_menu_switcher {
                    switcher.query.push(value);
                    switcher.selected = 0;
                }
            }
            _ => {}
        }
    }

    fn move_top_menu_switcher_selection(&mut self, delta: isize) {
        let Some(query) = self
            .top_menu_switcher
            .as_ref()
            .map(|switcher| switcher.query.clone())
        else {
            return;
        };
        let len = self.top_menu_switcher_candidates_for_query(&query).len();
        if let Some(switcher) = &mut self.top_menu_switcher {
            switcher.selected = move_wrapping(switcher.selected, len, delta);
        }
    }

    fn submit_top_menu_switcher_selection(&mut self) {
        let Some(switcher) = &self.top_menu_switcher else {
            return;
        };
        let candidates = self.top_menu_switcher_candidates_for_query(&switcher.query);
        let selected = switcher.selected.min(candidates.len().saturating_sub(1));
        let Some(candidate) = candidates.get(selected) else {
            self.status = "no matching top menu item".to_string();
            return;
        };

        let key = candidate.key.clone();
        let label = candidate.label.clone();
        self.top_menu_switcher = None;
        self.switch_top_menu_view(key);
        self.status = format!("top menu switched: {label}");
    }

    fn top_menu_switcher_candidates(&self) -> Vec<ViewTab> {
        self.view_tabs()
    }

    fn top_menu_switcher_candidates_for_query(&self, query: &str) -> Vec<ViewTab> {
        self.top_menu_switcher_candidates()
            .into_iter()
            .filter(|view| project_switcher_candidate_matches(view, query))
            .collect()
    }

    fn show_project_switcher(&mut self) {
        let candidates = self.project_switcher_candidates();
        if candidates.is_empty() {
            self.project_switcher = None;
            self.status = "no configured projects".to_string();
            return;
        }

        let selected = candidates
            .iter()
            .position(|candidate| candidate.key == self.active_view)
            .unwrap_or(0);
        self.finish_details_visit(Instant::now());
        self.command_palette = None;
        self.top_menu_switcher = None;
        self.recent_items_dialog = None;
        self.project_add_dialog = None;
        self.project_remove_dialog = None;
        self.cache_clear_dialog = None;
        self.project_switcher = Some(ProjectSwitcher {
            query: String::new(),
            selected,
        });
        self.status = "project switch".to_string();
    }

    fn dismiss_project_switcher(&mut self) {
        self.project_switcher = None;
        self.status = "project switch cancelled".to_string();
    }

    fn handle_project_switcher_key(&mut self, key: KeyEvent) {
        match key.code {
            KeyCode::Esc => self.dismiss_project_switcher(),
            KeyCode::Enter => self.submit_project_switcher_selection(),
            KeyCode::Down | KeyCode::Tab => self.move_project_switcher_selection(1),
            KeyCode::Up | KeyCode::BackTab => self.move_project_switcher_selection(-1),
            KeyCode::PageDown => self.move_project_switcher_selection(8),
            KeyCode::PageUp => self.move_project_switcher_selection(-8),
            KeyCode::Backspace => {
                if let Some(switcher) = &mut self.project_switcher {
                    switcher.query.pop();
                    switcher.selected = 0;
                }
            }
            KeyCode::Char(value)
                if !key.modifiers.contains(KeyModifiers::CONTROL)
                    && !key.modifiers.contains(KeyModifiers::ALT) =>
            {
                if let Some(switcher) = &mut self.project_switcher {
                    switcher.query.push(value);
                    switcher.selected = 0;
                }
            }
            _ => {}
        }
    }

    fn move_project_switcher_selection(&mut self, delta: isize) {
        let Some(query) = self
            .project_switcher
            .as_ref()
            .map(|switcher| switcher.query.clone())
        else {
            return;
        };
        let len = self.project_switcher_candidates_for_query(&query).len();
        if let Some(switcher) = &mut self.project_switcher {
            switcher.selected = move_wrapping(switcher.selected, len, delta);
        }
    }

    fn submit_project_switcher_selection(&mut self) {
        let Some(switcher) = &self.project_switcher else {
            return;
        };
        let candidates = self.project_switcher_candidates_for_query(&switcher.query);
        let selected = switcher.selected.min(candidates.len().saturating_sub(1));
        let Some(candidate) = candidates.get(selected) else {
            self.status = "no matching project".to_string();
            return;
        };

        let key = candidate.key.clone();
        let label = candidate.label.clone();
        self.project_switcher = None;
        self.switch_project_view(key);
        self.status = format!("project switched: {label}");
    }

    fn project_switcher_candidates(&self) -> Vec<ViewTab> {
        self.view_tabs()
            .into_iter()
            .filter(|view| view.key.starts_with("repo:"))
            .collect()
    }

    fn project_switcher_candidates_for_query(&self, query: &str) -> Vec<ViewTab> {
        self.project_switcher_candidates()
            .into_iter()
            .filter(|view| project_switcher_candidate_matches(view, query))
            .collect()
    }

