        app.focus_list();
        let base = themed_fg_style(Color::DarkGray);

        assert!(app.has_unread_notifications());
        assert!(
            view_tabs_title_style(&app, base)
                .add_modifier
                .contains(Modifier::BOLD)
        );

        app.sections[1].items[0].unread = Some(false);

