    fn recent_item(
        id: &str,
        kind: ItemKind,
        repo: &str,
        number: u64,
        title: &str,
        visited_at: i64,
    ) -> RecentItem {
        let path_kind = match kind {
            ItemKind::Issue => "issues",
            _ => "pull",
        };
        RecentItem {
            id: id.to_string(),
            kind,
            repo: repo.to_string(),
            number,
            title: title.to_string(),
            url: format!("https://github.com/{repo}/{path_kind}/{number}"),
            visited_at: DateTime::from_timestamp(visited_at, 0).unwrap(),
        }
    }

